globalThis.__BQ = {"kalp":{"lise":{"kolay":[{"q":"İnsan kalbinde kaç tane kulakçık (atriyum) ve kaç tane karıncık (ventrikül) bulunur?","steps":[{"t":"Kalbin boşlukları","a":"Kalp 4 boşluklu bir organdır","d":"Memeli kalbi üstte iki, altta iki olmak üzere toplam dört boşluktan oluşur. Üstteki boşluklar kanı toplar, alttakiler kanı pompalar."},{"t":"Üst ve alt boşlukların adları","a":"2 kulakçık + 2 karıncık","d":"Üstteki kan toplayan iki boşluğa kulakçık (atriyum) denir. Alttaki güçlü kasılarak kanı pompalayan iki boşluğa ise karıncık (ventrikül) denir."}],"ans":"2 kulakçık (atriyum) ve 2 karıncık (ventrikül) bulunur."},{"q":"Kalbin en kalın ve güçlü kas tabakası hangisidir?","steps":[{"t":"Kalp duvarının katmanları","a":"Üç tabaka vardır","d":"Kalp duvarı dıştan içe perikart, miyokart ve endokart olmak üzere üç tabakadan oluşur. Her tabakanın farklı bir görevi vardır."},{"t":"Kasılmadan sorumlu tabaka","a":"Miyokart en kalın kas tabakasıdır","d":"Ortadaki miyokart, kalp kası hücrelerinden oluşan kalın bir tabakadır. Kalbin kasılıp kanı pompalama gücünü bu tabaka sağladığı için en kalın ve güçlü katmandır."}],"ans":"Miyokart (kalp kası tabakası)."},{"q":"Kalbin dış yüzeyini saran koruyucu zara ne ad verilir?","steps":[{"t":"Kalbi saran yapı","a":"Dış tabaka aranır","d":"Kalbin en dışında onu çevreleyen ince ve dayanıklı bir zar bulunur. Bu zar kalbi dış etkilere karşı korur ve göğüs boşluğunda sabit tutar."},{"t":"Zarın adı ve işlevi","a":"Perikart","d":"Bu zara perikart denir. İçindeki sıvı sayesinde kalp kasılıp gevşerken sürtünme azalır ve hareket kolaylaşır."}],"ans":"Perikart."},{"q":"Kulakçık ile karıncık arasındaki kapakçıkların görevi nedir?","steps":[{"t":"Kapakçığın konumu","a":"Kulakçık-karıncık arasında yer alır","d":"Her kulakçık ile altındaki karıncık arasında bir kapakçık bulunur. Sağda triküspit, solda biküspit (mitral) kapak yer alır."},{"t":"Kapakçığın işlevi","a":"Kanın geri kaçmasını engeller","d":"Karıncık kasıldığında bu kapakçıklar kapanır ve kanın yeniden kulakçığa dönmesini önler. Böylece kan tek yönde, ileriye doğru akar."}],"ans":"Kanın karıncıktan kulakçığa geri kaçmasını önlerler."},{"q":"Kalbi besleyen damarlara ne ad verilir?","steps":[{"t":"Kalbin beslenme ihtiyacı","a":"Kalp kası da beslenmelidir","d":"Kalp sürekli çalışan bir kas olduğu için bol oksijen ve besine ihtiyaç duyar. İçinden geçen kan kalp duvarını yeterince besleyemez."},{"t":"Besleyen damarların adı","a":"Koroner damarlar","d":"Kalp kasını besleyen atardamarlara koroner damarlar denir. Bu damarlar tıkanırsa kalp kası oksijensiz kalır ve kalp krizi oluşabilir."}],"ans":"Koroner damarlar."},{"q":"Kalbin kasılma evresine ne ad verilir?","steps":[{"t":"Kalbin iki temel hareketi","a":"Kasılma ve gevşeme","d":"Kalp düzenli olarak kasılıp gevşeyerek kanı pompalar. Bu iki evre belirli sırayla tekrarlanır."},{"t":"Kasılma evresinin adı","a":"Sistol","d":"Kalbin kasıldığı ve kanı damarlara pompaladığı evreye sistol denir. Bu evrede kalp boşlukları küçülür ve kan dışarı itilir."}],"ans":"Sistol."},{"q":"Kalbin gevşeme evresine ne ad verilir?","steps":[{"t":"Pompalamadan sonraki aşama","a":"Kalp gevşer ve dolar","d":"Kasılmanın ardından kalp kası gevşer. Bu sırada boşluklar genişler ve yeniden kanla dolar."},{"t":"Gevşeme evresinin adı","a":"Diyastol","d":"Kalbin gevşeyip kanla dolduğu evreye diyastol denir. Diyastol olmadan kalp tekrar pompalayacak kanı toplayamaz."}],"ans":"Diyastol."},{"q":"Sağ kulakçık ile sağ karıncık arasındaki kapağın adı nedir?","steps":[{"t":"Kapağın konumu","a":"Kalbin sağ tarafı","d":"Kalbin sağ tarafında üstteki kulakçık ile alttaki karıncık arasında bir kapakçık bulunur. Bu kapak kirli kanın akış yönünü düzenler."},{"t":"Kapağın adı","a":"Triküspit (üç yapraklı) kapak","d":"Bu kapağa triküspit kapak denir, çünkü üç yapraktan oluşur. Sağ karıncık kasıldığında kapanarak kanın sağ kulakçığa geri kaçmasını önler."}],"ans":"Triküspit (üç yaprakçıklı) kapak."},{"q":"Sol kulakçık ile sol karıncık arasındaki kapağın adı nedir?","steps":[{"t":"Kapağın konumu","a":"Kalbin sol tarafı","d":"Kalbin sol tarafında kulakçık ile karıncık arasında bir kapak yer alır. Bu kapak temiz kanın geri kaçmasını engeller."},{"t":"Kapağın adı","a":"Biküspit (mitral) kapak","d":"Bu kapağa biküspit ya da mitral kapak denir, çünkü iki yaprakçıktan oluşur. Sol karıncık kasıldığında kapanır."}],"ans":"Biküspit (mitral) kapak."},{"q":"Kalbin iç yüzeyini döşeyen ince tabakanın adı nedir?","steps":[{"t":"Kalp duvarının iç katmanı","a":"En içteki tabaka aranır","d":"Kalp duvarının en iç yüzeyi, kanla doğrudan temas eden ince bir tabaka ile kaplıdır. Bu tabaka boşlukların iç yüzünü düzgün hale getirir."},{"t":"Tabakanın adı","a":"Endokart","d":"Bu iç tabakaya endokart denir. Düzgün yüzeyi sayesinde kanın kalp içinde sürtünmeden akmasını sağlar."}],"ans":"Endokart."},{"q":"Kalbin sol tarafının duvarı neden sağ tarafından daha kalındır?","steps":[{"t":"İki tarafın görevi","a":"Sol taraf tüm vücuda kan gönderir","d":"Kalbin sol karıncığı kanı tüm vücuda pompalar. Sağ karıncık ise yalnızca akciğerlere kan gönderir."},{"t":"Kalınlık ile basınç ilişkisi","a":"Daha fazla güç için kalın duvar","d":"Tüm vücuda kan göndermek yüksek basınç gerektirir. Bu nedenle sol karıncığın kas tabakası daha kalın ve güçlüdür."}],"ans":"Sol karıncık kanı tüm vücuda pompaladığı için daha yüksek basınç gerekir, bu yüzden duvarı kalındır."},{"q":"Kalbin kasılıp gevşemesinin bir kez tamamlanmasına ne ad verilir?","steps":[{"t":"Tek bir döngü","a":"Sistol + diyastol","d":"Kalbin bir kez kasılıp ardından gevşemesi tek bir döngü oluşturur. Bu döngü sürekli tekrarlanarak kalbin çalışmasını sağlar."},{"t":"Döngünün adı","a":"Kalp döngüsü (kardiyak siklus)","d":"Bir sistol ve bir diyastolden oluşan bu tam tura kalp döngüsü denir. Her döngüde kalp kanı toplar ve pompalar."}],"ans":"Kalp döngüsü (kardiyak siklus)."},{"q":"Perikart zarının içindeki sıvının görevi nedir?","steps":[{"t":"Perikart ve sıvısı","a":"Zar içinde sıvı bulunur","d":"Perikart zarının iki yaprağı arasında az miktarda sıvı bulunur. Kalp bu sıvının içinde gibi kasılıp gevşer."},{"t":"Sıvının işlevi","a":"Sürtünmeyi azaltır","d":"Bu sıvı, kalp her atışında oluşan sürtünmeyi azaltır. Böylece kalp zarar görmeden rahatça hareket eder."}],"ans":"Kalp kasılıp gevşerken oluşan sürtünmeyi azaltmak."},{"q":"Kalbin kulakçıkları mı yoksa karıncıkları mı daha kalın duvarlıdır, neden?","steps":[{"t":"Görev farkı","a":"Karıncıklar kanı pompalar","d":"Kulakçıklar kanı sadece alttaki karıncıklara aktarır. Karıncıklar ise kanı uzaklara, vücuda ve akciğerlere pompalar."},{"t":"Kalınlık sonucu","a":"Karıncık duvarları daha kalın","d":"Daha güçlü pompalama gerektiği için karıncık duvarları kulakçıklara göre çok daha kalındır. Kalın kas tabakası yüksek basınç üretir."}],"ans":"Karıncıklar daha kalın duvarlıdır, çünkü kanı uzak bölgelere yüksek basınçla pompalarlar."},{"q":"Kalp atardamarların (aort ve pulmoner) çıkışındaki kapakçıkların adı ve görevi nedir?","steps":[{"t":"Kapakların konumu","a":"Karıncık çıkışında","d":"Sol karıncıktan aorta, sağ karıncıktan akciğer atardamarına geçişte birer kapak bulunur. Bunlar atardamarların başlangıcında yer alır."},{"t":"Adı ve işlevi","a":"Yarım ay (semilunar) kapaklar","d":"Bu kapaklara yarım ay (semilunar) kapaklar denir. Karıncıklar gevşediğinde kapanarak pompalanan kanın geri dönmesini engellerler."}],"ans":"Yarım ay (semilunar) kapaklar; pompalanan kanın karıncığa geri dönmesini önlerler."}],"zor":[{"q":"Sol karıncık duvarının sağ karıncıktan kalın olması hangi fiziksel ilkeyle açıklanır?","steps":[{"t":"İki karıncığın görev alanı","a":"Sol vücuda, sağ akciğere pompalar","d":"Sol karıncık kanı tüm vücuda göndermek zorundadır, bu da uzun bir damar ağıdır. Sağ karıncık ise kanı yalnızca yakındaki akciğerlere ulaştırır."},{"t":"Basınç gereksinimi","a":"Sol taraf yüksek basınç üretmeli","d":"Uzun yola ve yüksek dirence karşı kan göndermek daha fazla basınç gerektirir. Basınç, kasın ürettiği kuvvetin alana oranıyla ilişkilidir."},{"t":"Kas kalınlığı sonucu","a":"Kalın duvar yüksek basınç sağlar","d":"Daha fazla kas lifi daha güçlü kasılma ve yüksek basınç üretir. Bu nedenle sol karıncığın miyokardı belirgin biçimde kalınlaşmıştır."}],"ans":"Sol karıncık vücuda yüksek basınçla kan pompalamak zorunda olduğundan, daha güçlü kasılma için duvarı kalınlaşmıştır."},{"q":"Koroner damarların tıkanması neden kalp krizine yol açar, mekanizmayı açıklayınız.","steps":[{"t":"Koronerlerin görevi","a":"Kalp kasını besler","d":"Koroner damarlar kalp kasına oksijen ve besin taşır. Kalp kası sürekli çalıştığı için kesintisiz kan akışına ihtiyaç duyar."},{"t":"Tıkanmanın etkisi","a":"Kas oksijensiz kalır","d":"Bir koroner damar tıkandığında, beslediği bölgedeki kalp kası oksijensiz kalır. Oksijensiz kalan hücreler enerji üretemez ve görevini sürdüremez."},{"t":"Doku ölümü","a":"Miyokart hücreleri ölür","d":"Oksijensizlik kısa sürede kalp kası hücrelerinin ölümüne yol açar. Bu doku ölümüne kalp krizi (miyokart enfarktüsü) denir."}],"ans":"Tıkanan koroner damarın beslediği kalp kası oksijensiz kalır ve hücreler ölür; bu durum kalp krizidir."},{"q":"Kalp döngüsünde kapakçıkların açılıp kapanması kalp seslerini nasıl oluşturur?","steps":[{"t":"Birinci ses kaynağı","a":"AV kapakların kapanması","d":"Karıncıklar kasıldığında (sistol) kulakçık-karıncık arası kapaklar kapanır. Bu kapanma ilk kalp sesini (lup) oluşturur."},{"t":"İkinci ses kaynağı","a":"Yarım ay kapakların kapanması","d":"Karıncıklar gevşediğinde aort ve pulmoner kapaklar kapanır. Bu kapanma ikinci kalp sesini (dup) meydana getirir."},{"t":"Seslerin anlamı","a":"Kapak kapanmaları lup-dup sesini verir","d":"Böylece her döngüde art arda iki ses duyulur. Bu sesler kapakların düzgün çalışıp çalışmadığı hakkında bilgi verir."}],"ans":"Kalp sesleri, sistolde AV kapakların ve diyastolde yarım ay kapaklarının kapanmasıyla oluşan lup-dup sesleridir."},{"q":"Kalbin sağ ve sol tarafı arasında erişkinde neden doğrudan kan geçişi olmamalıdır?","steps":[{"t":"İki tarafın kan içeriği","a":"Sağ kirli, sol temiz kan taşır","d":"Kalbin sağ tarafında oksijence fakir kirli kan, sol tarafında oksijence zengin temiz kan bulunur. Bu iki kan septum (perde) ile ayrılır."},{"t":"Karışmanın sonucu","a":"Oksijen taşıma verimi düşer","d":"Eğer iki taraf birbirine açılırsa temiz ve kirli kan karışır. Vücuda giden kanın oksijen miktarı azalır."},{"t":"Verim ve sağlık","a":"Tam ayrım yüksek verim sağlar","d":"Tam ayrılmış dolaşımda dokulara her zaman bol oksijenli kan ulaşır. Bu nedenle septumdaki bir delik (örneğin doğumsal kalp deliği) verimi düşürür."}],"ans":"Sağ taraf kirli, sol taraf temiz kan taşır; karışırsa oksijen taşıma verimi düşeceğinden iki taraf septumla ayrılmıştır."},{"q":"Diyastol sırasında karıncıkların kanla dolması hangi olaylarla gerçekleşir?","steps":[{"t":"Karıncığın gevşemesi","a":"Basınç düşer","d":"Diyastolde karıncık kası gevşer ve boşluğu genişler. Genişleyen boşlukta basınç, üstteki kulakçığa göre düşer."},{"t":"Basınç farkıyla akış","a":"Kan kulakçıktan karıncığa geçer","d":"Basınç farkı nedeniyle AV kapaklar açılır ve kan kulakçıktan karıncığa akar. Bu pasif dolum karıncığın büyük kısmını doldurur."},{"t":"Kulakçık kasılması","a":"Son dolum sağlanır","d":"Diyastolün sonunda kulakçıklar hafifçe kasılarak kalan kanı da karıncığa iter. Böylece karıncık bir sonraki sistol için tam dolmuş olur."}],"ans":"Karıncık gevşeyip basıncı düşünce AV kapaklar açılır, kan kulakçıktan akar ve kulakçık kasılmasıyla dolum tamamlanır."},{"q":"Kalp duvarının üç tabakasını işlevleriyle birlikte açıklayınız.","steps":[{"t":"Dış tabaka","a":"Perikart korur","d":"En dıştaki perikart, kalbi saran koruyucu zardır. İçindeki sıvı sürtünmeyi azaltır ve kalbi göğüs boşluğunda sabitler."},{"t":"Orta tabaka","a":"Miyokart kasılır","d":"Ortadaki miyokart kalp kası hücrelerinden oluşur. Kasılıp gevşeyerek kanın pompalanmasını sağlayan asıl tabakadır."},{"t":"İç tabaka","a":"Endokart düzgün yüzey sağlar","d":"En içteki endokart, boşlukların iç yüzeyini kaplar. Düzgün yapısı sayesinde kan sürtünmeden akar ve pıhtılaşma riski azalır."}],"ans":"Perikart korur ve sürtünmeyi azaltır, miyokart kasılıp kanı pompalar, endokart iç yüzeyi düzgünleştirir."},{"q":"Kalp neden kendi içinden geçen kanla beslenemez, koroner dolaşıma ihtiyaç duyar?","steps":[{"t":"İç kanla beslenme sorunu","a":"Endokart madde geçişine elverişsiz","d":"Kalp boşluklarındaki kan, kalın miyokart tabakasına yeterince madde geçiremez. Endokart ve kas kalınlığı difüzyonla beslenmeyi sınırlar."},{"t":"Kalbin yüksek ihtiyacı","a":"Sürekli çalışan kas çok oksijen ister","d":"Kalp durmadan çalışan bir kas olduğu için çok yüksek oranda oksijen ve besin tüketir. İç kandan sağlanan az miktar bu ihtiyacı karşılamaz."},{"t":"Koroner çözümü","a":"Ayrı bir damar ağı gerekir","d":"Bu nedenle kalp kası, aorttan ayrılan koroner damarlarla ayrıca beslenir. Koroner ağ, kalbin tüm kasına yeterli kan ulaştırır."}],"ans":"Kalın miyokart iç kandan yeterince beslenemediği ve kalbin oksijen ihtiyacı çok yüksek olduğu için koroner damarlarla ayrı beslenir."},{"q":"Bir kalp döngüsünde kulakçık ve karıncık kasılmalarının zamanlaması neden farklıdır?","steps":[{"t":"Doğru sıralamanın önemi","a":"Önce kulakçık, sonra karıncık","d":"Kulakçıkların ve karıncıkların aynı anda kasılması verimsiz olurdu. Kanın doğru yönde akması için belirli bir sıra gerekir."},{"t":"Kulakçık kasılması","a":"Karıncığı doldurur","d":"Önce kulakçıklar kasılır ve karıncıklara kanı tam olarak doldurur. Bu sayede karıncık kasılmadan önce maksimum kanla dolar."},{"t":"Karıncık kasılması","a":"Kanı damarlara pompalar","d":"Kısa bir gecikmeden sonra karıncıklar kasılır ve kanı damarlara gönderir. Bu gecikme AV düğümdeki iletinin yavaşlamasıyla sağlanır."}],"ans":"Önce kulakçıklar kasılıp karıncığı doldurur, ardından karıncıklar kasılıp kanı pompalar; bu gecikme verimli pompalamayı sağlar."},{"q":"Triküspit ve biküspit kapaklarının yaprak sayısının farklı olmasının nedeni nedir?","steps":[{"t":"İki kapağın yeri","a":"Sağ ve sol AV açıklığı","d":"Triküspit kapak sağda, biküspit (mitral) kapak solda yer alır. Her ikisi de kulakçık-karıncık arası açıklığı kapatır."},{"t":"Basınç farkı","a":"Sol tarafta basınç yüksek","d":"Sol karıncık çok yüksek basınç ürettiği için kapağın daha sağlam ve sızdırmaz kapanması gerekir. İki yaprakçıklı yapı bu yüksek basınca daha iyi dayanır."},{"t":"Yapısal uyum","a":"Yaprak sayısı basınca uyumlu","d":"Sağ tarafta basınç düşük olduğundan üç yaprakçıklı yapı yeterlidir. Böylece her kapak bulunduğu bölgenin basıncına uygun şekilde yapılanmıştır."}],"ans":"Sol tarafta basınç yüksek olduğundan mitral kapak daha sağlam iki yapraklıdır; sağ tarafta basınç düşük olduğundan üç yapraklı triküspit yeterlidir."},{"q":"Kalp pili (kalbin kendi sistolik aktivitesi) durduğunda neden tüm vücut etkilenir?","steps":[{"t":"Kalbin merkezi rolü","a":"Tüm dolaşımı kalp sürdürür","d":"Kalp, kanı vücudun her yerine pompalayan merkezi pompadır. Tüm doku ve organlar kalbin pompaladığı kana bağımlıdır."},{"t":"Pompalama durunca","a":"Kan akışı durur","d":"Kalp kasılmayı durdurursa kan dolaşımı tümüyle durur. Dokulara oksijen ve besin ulaşamaz, atıklar uzaklaştırılamaz."},{"t":"Yaşamsal sonuç","a":"Organlar hızla zarar görür","d":"Özellikle beyin gibi oksijene çok bağımlı organlar dakikalar içinde geri dönüşsüz zarar görür. Bu nedenle kalbin durması tüm vücut için yaşamsal bir tehdittir."}],"ans":"Kalp tüm vücudun tek pompasıdır; durunca kan akışı kesilir ve başta beyin olmak üzere tüm organlar oksijensiz kalarak zarar görür."},{"q":"Kalp kası hücrelerinin yorulmadan sürekli çalışabilmesini sağlayan yapısal özellikler nelerdir?","steps":[{"t":"Mitokondri yoğunluğu","a":"Bol enerji üretimi","d":"Kalp kası hücreleri çok sayıda mitokondri içerir. Bu organeller oksijenli solunumla sürekli ve bol ATP üretir."},{"t":"Kan ile zengin beslenme","a":"Koroner ağ yoğundur","d":"Kalp kası koroner damarlarla yoğun şekilde beslenir. Bu sayede hücreler kesintisiz oksijen ve besin alır."},{"t":"Hücreler arası bağlantı","a":"Disk benzeri bağlantılar uyumu sağlar","d":"Kalp kası hücreleri ara disklerle birbirine bağlıdır ve uyarıyı hızla iletir. Böylece hücreler birlikte ve düzenli kasılarak yorulmadan çalışır."}],"ans":"Bol mitokondri, koroner ağla zengin beslenme ve hücreleri birbirine bağlayan ara diskler kalbin yorulmadan çalışmasını sağlar."},{"q":"Sistol ve diyastol basınçları arasındaki fark vücut için neden önemlidir?","steps":[{"t":"İki basınç değeri","a":"Sistolik ve diyastolik basınç","d":"Sistolde kalp kasılırken damarlarda basınç yükselir, buna sistolik (büyük) basınç denir. Diyastolde kalp gevşerken basınç düşer, buna diyastolik (küçük) basınç denir."},{"t":"Sürekli akışın sağlanması","a":"Diyastolik basınç akışı devam ettirir","d":"Kalp gevşerken bile damarlardaki esneklik sayesinde belli bir basınç korunur. Bu sayede kan dokulara kalp atışları arasında da akmaya devam eder."},{"t":"Sağlık göstergesi","a":"Fark dengeli olmalı","d":"Sistolik ve diyastolik basınç arasındaki uygun fark sağlıklı dolaşımı gösterir. Aşırı yüksek veya düşük değerler kalp ve damar sorunlarına işaret eder."}],"ans":"Sistolik basınç kasılma anının, diyastolik basınç gevşeme anının basıncıdır; aralarındaki denge kanın sürekli ve sağlıklı akmasını sağlar."},{"q":"Kalbin AV kapakları, karıncık kasıldığında neden ters dönüp kulakçığa açılmaz?","steps":[{"t":"Kapakların bağlantısı","a":"İp benzeri yapılarla tutulurlar","d":"AV kapaklarının yaprakçıkları, korda tendinea adı verilen ipliksi yapılarla karıncık duvarına bağlıdır. Bu ipler kapağın hareketini sınırlar."},{"t":"Papiller kas desteği","a":"Kaslar ipleri gergin tutar","d":"Karıncık kasıldığında papiller kaslar da kasılır ve bu iplikleri gergin tutar. Böylece kapak yaprakçıkları belirli sınırın ötesine geçemez."},{"t":"Ters açılmanın önlenmesi","a":"Kapak kulakçığa devrilmez","d":"Bu mekanizma sayesinde yüksek basınçta bile kapak kulakçığa doğru devrilmez. Kan geri kaçamaz ve tek yönde damarlara pompalanır."}],"ans":"Korda tendinea ipleri ve papiller kaslar kapakları gergin tutarak yüksek basınçta kulakçığa doğru devrilmelerini engeller."},{"q":"Kalbin sol karıncığından çıkan ana atardamar hangisidir ve nereye kan gönderir?","steps":[{"t":"Sol karıncığın görevi","a":"Vücuda temiz kan pompalar","d":"Sol karıncık, oksijence zengin temiz kanı tüm vücuda göndermekle görevlidir. Bunun için büyük ve güçlü bir atardamara ihtiyaç vardır."},{"t":"Ana atardamarın adı","a":"Aort","d":"Sol karıncıktan çıkan en büyük atardamar aorttur. Aort, vücudun en kalın ve en basınçlı damarıdır."},{"t":"Dağıtım","a":"Tüm organlara dallanır","d":"Aort, dallanarak tüm organ ve dokulara temiz kan ulaştırır. Koroner damarlar da aortun başlangıcından ayrılarak kalbi besler."}],"ans":"Sol karıncıktan aort çıkar ve oksijence zengin kanı dallanarak tüm vücuda dağıtır."},{"q":"Kalbin kapakçıklarında oluşan bir kaçak (yetmezlik) dolaşımı nasıl etkiler?","steps":[{"t":"Sağlıklı kapağın görevi","a":"Kanın geri kaçmasını önler","d":"Sağlıklı kapaklar tam kapanarak kanın tek yönde akmasını sağlar. Bu sayede pompalanan kanın tamamı ileriye gider."},{"t":"Kaçak durumu","a":"Bir miktar kan geri kaçar","d":"Kapak tam kapanmazsa pompalanan kanın bir kısmı geri kaçar. Böylece her atışta ileriye giden kan miktarı azalır."},{"t":"Telafi ve yorulma","a":"Kalp fazladan çalışır","d":"Vücudun ihtiyacını karşılamak için kalp daha fazla çalışmak zorunda kalır. Uzun vadede bu durum kalbin yorulmasına ve büyümesine yol açabilir."}],"ans":"Kapak kaçağında kanın bir kısmı geri kaçar, ileri giden kan azalır ve kalp telafi için fazladan çalışarak yorulur."}]}},"damarlar":{"lise":{"kolay":[{"q":"Kanı kalpten vücuda doğru götüren damarlara ne ad verilir?","steps":[{"t":"Akış yönü","a":"Kalpten dışarı","d":"Bazı damarlar kanı kalpten alıp vücut bölgelerine taşır. Bu damarlarda kan kalpten uzaklaşacak yönde akar."},{"t":"Damarın adı","a":"Atardamar (arter)","d":"Kanı kalpten vücuda götüren damarlara atardamar denir. Kalbin pompaladığı yüksek basınca dayanacak şekilde kalın ve esnek yapıdadırlar."}],"ans":"Atardamarlar (arterler)."},{"q":"Kanı vücuttan kalbe doğru getiren damarlara ne ad verilir?","steps":[{"t":"Akış yönü","a":"Vücuttan kalbe","d":"Bazı damarlar kanı dokulardan toplayıp kalbe geri taşır. Bu damarlarda kan kalbe doğru akar."},{"t":"Damarın adı","a":"Toplardamar (ven)","d":"Kanı kalbe getiren damarlara toplardamar denir. İçlerinde kanın geri kaçmasını önleyen kapakçıklar bulunur."}],"ans":"Toplardamarlar (venler)."},{"q":"Madde alışverişinin gerçekleştiği en ince damarlara ne ad verilir?","steps":[{"t":"Damarın boyutu","a":"En ince damarlar","d":"Dokuların içinde tek sıra hücreden oluşan çok ince damarlar bulunur. Bu damarların duvarı son derece incedir."},{"t":"Görevi ve adı","a":"Kılcal damar","d":"Bu en ince damarlara kılcal damar denir. İnce duvarları sayesinde kan ile dokular arasında oksijen, besin ve atık alışverişi burada yapılır."}],"ans":"Kılcal damarlar (kapillerler)."},{"q":"Toplardamarların içinde kapakçık bulunmasının nedeni nedir?","steps":[{"t":"Toplardamarda basınç","a":"Basınç düşüktür","d":"Toplardamarlarda kan basıncı atardamarlara göre çok düşüktür. Bu düşük basınç kanı kalbe doğru itmekte yetersiz kalır."},{"t":"Kapakçığın görevi","a":"Geri kaçışı önler","d":"Kapakçıklar kanın yer çekimine karşı geri kaçmasını engeller. Böylece kan, kaslarla da yardımıyla tek yönde kalbe doğru ilerler."}],"ans":"Düşük basınçta kanın geri kaçmasını önlemek için kapakçık bulunur."},{"q":"Atardamarların duvarı toplardamarlardan neden daha kalındır?","steps":[{"t":"Taşınan basınç","a":"Atardamarda basınç yüksek","d":"Atardamarlar kalbin pompaladığı yüksek basınçlı kanı taşır. Her kalp atışında bu damarlar güçlü bir basınca maruz kalır."},{"t":"Kalın duvarın işlevi","a":"Yüksek basınca dayanır","d":"Kalın ve esnek duvar bu yüksek basınca dayanmayı ve kanı ileriye itmeyi sağlar. Bu yüzden atardamar duvarları toplardamarlardan kalındır."}],"ans":"Atardamarlar yüksek basınçlı kan taşıdığı için duvarları kalın ve esnektir."},{"q":"Nabız nedir ve nasıl oluşur?","steps":[{"t":"Kalp atışı ve damar","a":"Kalp kanı itince","d":"Kalp her kasıldığında atardamarlara basınçlı kan pompalar. Bu basınç dalgası atardamar duvarlarında bir genişleme yaratır."},{"t":"Hissedilen atış","a":"Nabız bu dalgadır","d":"Atardamar duvarındaki bu ritmik genişleme nabız olarak hissedilir. Bilekteki atardamardan dakikadaki kalp atış sayısı sayılabilir."}],"ans":"Nabız, kalbin her atışında atardamar duvarında oluşan ritmik genişlemedir."},{"q":"Kan basıncı en yüksek hangi damar türünde ölçülür?","steps":[{"t":"Basınç kaynağı","a":"Kalbe yakınlık","d":"Kan basıncı kalbin pompalama gücünden kaynaklanır. Kalbe en yakın ve doğrudan pompalanan kanı alan damarlarda basınç en yüksektir."},{"t":"Yüksek basınçlı damar","a":"Atardamarlar","d":"Atardamarlar doğrudan karıncıklardan kan aldığı için basınç en yüksek bu damarlardadır. Kılcal ve toplardamarlara doğru basınç giderek azalır."}],"ans":"Atardamarlarda."},{"q":"Kılcal damarların duvarının tek sıra hücreden oluşması neden önemlidir?","steps":[{"t":"İnce duvar yapısı","a":"Tek katlı hücre","d":"Kılcal damar duvarı yalnızca tek sıra hücreden oluşur. Bu, vücuttaki en ince damar duvarıdır."},{"t":"Madde geçişi","a":"Alışveriş kolaylaşır","d":"İnce duvar sayesinde oksijen, besin ve atık maddeler kolayca geçebilir. Böylece kan ile dokular arasındaki madde alışverişi verimli olur."}],"ans":"İnce duvar, kan ile dokular arasında madde alışverişinin kolayca yapılmasını sağlar."},{"q":"Atardamar, toplardamar ve kılcal damar arasında kan akış hızı nasıl sıralanır?","steps":[{"t":"Kesit alanı farkı","a":"Kılcalların toplam kesiti çok geniş","d":"Kılcal damarların sayısı çok fazla olduğu için toplam kesit alanları en geniştir. Geniş kesitte kan yayılır ve yavaşlar."},{"t":"Hız sıralaması","a":"Atardamar en hızlı, kılcal en yavaş","d":"Kan en hızlı atardamarlarda, en yavaş kılcal damarlarda akar; toplardamarda hız tekrar bir miktar artar. Kılcaldaki yavaşlık madde alışverişine zaman tanır."}],"ans":"En hızlı atardamarlarda, en yavaş kılcal damarlarda akar (toplardamarda hız yeniden artar)."},{"q":"Toplardamarlarda kanın kalbe dönüşüne yardımcı olan kas hareketi nedir?","steps":[{"t":"Düşük basınç sorunu","a":"Basınç kanı tek başına itemez","d":"Toplardamarlarda basınç düşük olduğu için kan tek başına kalbe ulaşmakta zorlanır. Özellikle bacaklarda kanın yer çekimine karşı yükselmesi gerekir."},{"t":"Kasların yardımı","a":"İskelet kasları sıkıştırır","d":"Çevredeki iskelet kasları kasıldığında toplardamarları sıkıştırır ve kanı yukarı iter. Kapakçıklar geri kaçışı önleyince kan kalbe doğru ilerler."}],"ans":"Çevredeki iskelet kaslarının kasılması toplardamarları sıkıştırarak kanı kalbe doğru iter."},{"q":"Atardamarların esnek olması hangi açıdan yararlıdır?","steps":[{"t":"Kalp atışındaki basınç dalgası","a":"Basınç ani yükselir","d":"Kalp kasıldığında atardamara aniden yüksek basınçlı kan girer. Bu ani basınç damar duvarını gerer."},{"t":"Esnekliğin yararı","a":"Basıncı dengeler","d":"Esnek duvar genişleyerek basıncı yumuşatır, kalp gevşerken ise büzülerek kanı ileri iter. Böylece atardamarlardaki kan akışı kesintisiz ve düzenli olur."}],"ans":"Esneklik, basınç dalgalarını yumuşatır ve kalp gevşerken bile kanın ileri akmasını sağlar."},{"q":"Kılcal damarlarda kanın yavaş akmasının canlı için faydası nedir?","steps":[{"t":"Yavaş akışın koşulu","a":"Geniş toplam kesit","d":"Kılcal damarlarda kan çok yavaş akar, çünkü toplam kesit alanı çok geniştir. Bu yavaşlık dokularla temas süresini uzatır."},{"t":"Madde alışverişine etkisi","a":"Yeterli zaman sağlar","d":"Yavaş akış sayesinde oksijen ve besinlerin dokulara, atıkların ise kana geçmesi için yeterli zaman doğar. Böylece madde alışverişi verimli gerçekleşir."}],"ans":"Yavaş akış, kan ile dokular arasında madde alışverişi için yeterli zaman sağlar."},{"q":"Vücutta oksijence en zengin kanı taşıyan damar türü ve örneği nedir?","steps":[{"t":"Temiz kanın çıkışı","a":"Sol karıncıktan aort","d":"Akciğerlerde oksijen alan temiz kan sol karıncığa, oradan aorta gönderilir. Aort vücudun en büyük atardamarıdır."},{"t":"Genel kural ve istisna","a":"Genelde atardamar temiz kan taşır","d":"Genel olarak atardamarlar temiz, toplardamarlar kirli kan taşır. Aort, oksijence en zengin kanı taşıyan damardır."}],"ans":"Atardamarlar (özellikle aort) oksijence en zengin kanı taşır."},{"q":"Akciğer atardamarı (pulmoner arter) genel kuralın neden bir istisnasıdır?","steps":[{"t":"Genel kural","a":"Atardamar genelde temiz kan taşır","d":"Çoğu atardamar oksijence zengin temiz kanı vücuda götürür. Bu yüzden \"atardamar temiz kan taşır\" kuralı yaygındır."},{"t":"Pulmoner arterin durumu","a":"Kirli kan taşır","d":"Akciğer atardamarı sağ karıncıktan çıkar ve oksijence fakir kirli kanı akciğerlere götürür. Atardamar olmasına rağmen kirli kan taşıdığı için istisnadır."}],"ans":"Akciğer atardamarı, atardamar olmasına rağmen kirli (oksijence fakir) kan taşıdığı için istisnadır."},{"q":"Damar duvarlarının kas ve bağ dokusu içermesi neden gereklidir?","steps":[{"t":"Damarın görevi","a":"Kan akışını düzenler","d":"Damarlar yalnızca pasif borular değildir, kan akışını ve basıncını düzenlerler. Bunun için duvarlarında kas ve bağ dokusu bulunur."},{"t":"Kas ve bağ dokunun işlevi","a":"Daralma-genişleme ve dayanıklılık","d":"Kas tabakası damarın daralıp genişlemesini sağlayarak kan akışını ayarlar. Bağ dokusu ise damara esneklik ve dayanıklılık kazandırır."}],"ans":"Kas dokusu damarın daralıp genişlemesini, bağ dokusu ise esneklik ve dayanıklılığı sağlar."}],"zor":[{"q":"Kan basıncının atardamardan kılcal ve toplardamara doğru azalmasının nedenlerini açıklayınız.","steps":[{"t":"Basıncın kaynağı","a":"Kalbin pompalaması","d":"Kan basıncı kalbin pompalama gücüyle oluşur ve atardamarlarda en yüksektir. Kalpten uzaklaştıkça bu basınç giderek tükenir."},{"t":"Sürtünme kaybı","a":"Damar direnci basıncı düşürür","d":"Kan damar duvarlarıyla sürtünerek ilerlerken enerji kaybeder. Özellikle çok dar ve çok sayıda olan kılcallarda direnç yüksektir ve basınç hızla düşer."},{"t":"Toplardamarda basınç","a":"En düşük basınç","d":"Kılcallardan sonra toplardamarlara ulaşan kanın basıncı çok düşmüştür. Bu yüzden toplardamarlarda kapakçık ve kas yardımı gerekir."}],"ans":"Kalpten uzaklaştıkça sürtünme ve direnç nedeniyle enerji kaybedildiğinden basınç atardamardan kılcala ve toplardamara doğru azalır."},{"q":"Kılcal damar duvarının yapısı, madde alışverişini nasıl optimize eder?","steps":[{"t":"Tek katlı duvar","a":"Çok ince yapı","d":"Kılcal damar duvarı tek sıra yassı epitel hücreden oluşur. Bu, madde geçişi için gereken mesafeyi en aza indirir."},{"t":"Yavaş akış","a":"Temas süresi uzun","d":"Kılcallarda kan çok yavaş aktığı için kan ile doku arasındaki temas süresi uzar. Bu uzun süre difüzyonla madde geçişini kolaylaştırır."},{"t":"Geniş yüzey","a":"Toplam alan çok büyük","d":"Vücuttaki milyonlarca kılcal damar çok geniş bir toplam yüzey oluşturur. Geniş yüzey, aynı anda çok miktarda madde alışverişine olanak verir."}],"ans":"İnce tek katlı duvar, yavaş akış ve geniş toplam yüzey birlikte madde alışverişini en verimli düzeye çıkarır."},{"q":"Toplardamarlarda kan dönüşünü sağlayan üç temel mekanizmayı açıklayınız.","steps":[{"t":"Kas pompası","a":"İskelet kasları sıkıştırır","d":"Hareket sırasında iskelet kasları toplardamarları sıkıştırarak kanı kalbe doğru iter. Bu mekanizma özellikle bacaklarda etkilidir."},{"t":"Kapakçıklar","a":"Tek yönlü akışı sağlar","d":"Toplardamar içindeki kapakçıklar kanın geri kaçmasını önler. Kas sıkıştırması ileri ittiğinde kapaklar geriye doğru kapanır."},{"t":"Solunum pompası","a":"Göğüs basıncı kanı çeker","d":"Nefes alırken göğüs boşluğundaki basınç düşer ve kanı kalbe doğru çeker. Bu üç mekanizma birlikte düşük basınçlı toplardamar kanını kalbe ulaştırır."}],"ans":"Kas pompası, kapakçıklar ve solunum pompası birlikte çalışarak düşük basınçlı toplardamar kanını kalbe geri döndürür."},{"q":"Bir kişinin uzun süre hareketsiz ayakta durması bacaklarda neden şişmeye yol açabilir?","steps":[{"t":"Hareketsizlik etkisi","a":"Kas pompası çalışmaz","d":"Hareketsiz durulduğunda bacak kasları kasılmaz ve toplardamarları sıkıştırmaz. Böylece kanın yukarı itilmesi sağlayan kas pompası devre dışı kalır."},{"t":"Kan birikmesi","a":"Bacakta kan göllenir","d":"Yer çekimi nedeniyle kan bacak toplardamarlarında birikir. Toplardamarlardaki basınç artar ve damarlar gerilir."},{"t":"Sıvı sızması","a":"Doku sıvısı artar ve şişme oluşur","d":"Artan basınç kılcallardan dokuya sıvı sızmasına yol açar. Dokuda biriken bu fazla sıvı bacaklarda şişlik (ödem) olarak görülür."}],"ans":"Hareketsizlikte kas pompası çalışmaz, kan bacakta göllenir, kılcallardan dokuya sıvı sızar ve şişme (ödem) oluşur."},{"q":"Atardamar sertleşmesi (damar duvarının esnekliğini yitirmesi) kan basıncını nasıl etkiler?","steps":[{"t":"Sağlıklı esnek damar","a":"Basıncı yumuşatır","d":"Sağlıklı atardamarlar esnektir ve kalp her kasıldığında genişleyerek basınç dalgasını yumuşatır. Böylece basınç aşırı yükselmez."},{"t":"Sertleşme etkisi","a":"Genişleme azalır","d":"Damar duvarı sertleştiğinde gelen kanla genişleyemez. Aynı miktar kan daha az esnek bir boruya girince basınç daha fazla yükselir."},{"t":"Sonuç","a":"Kan basıncı artar","d":"Esneklik kaybı nedeniyle sistolik kan basıncı yükselir. Kalp bu yüksek basınca karşı çalışmak zorunda kalır ve zamanla yorulur."}],"ans":"Sertleşen damar basınç dalgasını yumuşatamaz, böylece kan basıncı yükselir ve kalbin yükü artar."},{"q":"Atardamar ve toplardamar duvarlarındaki tabaka farkları işlevle nasıl ilişkilidir?","steps":[{"t":"Atardamar duvarı","a":"Kalın kas ve esnek doku","d":"Atardamarlar yüksek basınçlı kan taşıdığı için kalın kas ve bol esnek lif içerir. Bu yapı basınca dayanıp kanı ileri itmeyi sağlar."},{"t":"Toplardamar duvarı","a":"İnce duvar ve kapakçık","d":"Toplardamarlar düşük basınçlı kan taşıdığından duvarları ince, kas tabakası az gelişmiştir. Buna karşılık geri kaçışı önleyen kapakçıklar bulunur."},{"t":"Yapı-işlev uyumu","a":"Her damar görevine uygun","d":"Böylece atardamar yüksek basınca, toplardamar düşük basınçlı geri dönüşe göre yapılanmıştır. Yapı her zaman işlevi destekleyecek biçimde özelleşmiştir."}],"ans":"Atardamar yüksek basınç için kalın-esnek duvarlı, toplardamar düşük basınçlı dönüş için ince duvarlı ve kapakçıklıdır; yapı işleve uyumludur."},{"q":"Kan basıncının ölçümünde büyük (sistolik) ve küçük (diyastolik) tansiyon neyi gösterir?","steps":[{"t":"Sistolik değer","a":"Kasılma basıncı","d":"Büyük tansiyon, kalp kasıldığında atardamarlardaki en yüksek basıncı gösterir. Bu, kalbin pompalama gücünü yansıtır."},{"t":"Diyastolik değer","a":"Gevşeme basıncı","d":"Küçük tansiyon, kalp gevşerken atardamarlardaki en düşük basıncı gösterir. Bu değer damarların gevşeme anındaki direncini yansıtır."},{"t":"Birlikte değerlendirme","a":"İkisi birlikte sağlık göstergesi","d":"İki değer birlikte dolaşım sisteminin durumunu gösterir. Normal aralığın dışındaki değerler kalp ve damar hastalıklarına işaret edebilir."}],"ans":"Büyük tansiyon kasılma anının (sistolik), küçük tansiyon gevşeme anının (diyastolik) atardamar basıncını gösterir."},{"q":"Bir atardamarın daralması (vazokonstriksiyon) ile genişlemesi (vazodilatasyon) vücutta neyi düzenler?","steps":[{"t":"Damar kasının rolü","a":"Çapı değiştirir","d":"Atardamar duvarındaki düz kaslar kasılıp gevşeyerek damar çapını değiştirir. Bu çap değişimi kan akışını ve basıncı etkiler."},{"t":"Daralma etkisi","a":"Akış azalır, basınç artar","d":"Damar daralınca o bölgeye giden kan azalır ve genel kan basıncı yükselir. Soğukta deri damarlarının daralması ısı kaybını azaltır."},{"t":"Genişleme etkisi","a":"Akış artar, basınç düşer","d":"Damar genişleyince o bölgeye giden kan artar ve basınç düşer. Egzersizde kaslara giden damarların genişlemesi kaslara daha çok oksijen ulaştırır."}],"ans":"Damar daralması ve genişlemesi, bölgelere giden kan miktarını ve genel kan basıncını düzenleyerek vücut ihtiyaçlarına uyum sağlar."},{"q":"Aort gibi büyük bir atardamarın esnek liflerce zengin olması kan akışını nasıl sürekli kılar?","steps":[{"t":"Sistolde depolama","a":"Aort genişler","d":"Kalp kasıldığında aorta yüksek basınçlı kan girer ve esnek aort duvarı gerilerek genişler. Bu gerilme bir miktar enerjiyi depolar."},{"t":"Diyastolde geri verme","a":"Aort büzülür","d":"Kalp gevşediğinde aort duvarı eski haline dönerek büzülür. Depolanan enerji kanı ileri doğru iter."},{"t":"Sürekli akış","a":"Kesintisiz kan akışı","d":"Böylece kalp gevşerken bile kan ileriye akmaya devam eder. Aortun esnekliği kesikli pompalamayı sürekli akışa dönüştürür."}],"ans":"Aort sistolde gerilip enerji depolar, diyastolde büzülerek bu enerjiyi kana aktarır; böylece kesintili pompalama sürekli akışa dönüşür."},{"q":"Kılcal damar yataklarına giren ve çıkan kanın bileşimi neden farklıdır?","steps":[{"t":"Kılcala giren kan","a":"Oksijen ve besin açısından zengin","d":"Kılcal yatağa atardamar tarafından gelen kan oksijen ve besin maddeleri bakımından zengindir. Dokular bu maddelere ihtiyaç duyar."},{"t":"Madde alışverişi","a":"Difüzyonla geçiş","d":"Kılcal damarlarda oksijen ve besinler dokulara geçerken, karbondioksit ve atıklar dokulardan kana geçer. Bu alışveriş ince duvar üzerinden difüzyonla olur."},{"t":"Kılcaldan çıkan kan","a":"Atık ve karbondioksitçe zengin","d":"Alışveriş sonucu kılcaldan toplardamara geçen kan oksijence fakir, atık bakımından zengindir. Bu nedenle giriş ve çıkış kanının bileşimi farklıdır."}],"ans":"Kılcala giren kan oksijen/besin açısından zengindir; doku ile difüzyon sonucu çıkan kan oksijence fakir, karbondioksit ve atıkça zengin hale gelir."},{"q":"Toplardamar kapakçıklarının zarar görmesi (varis) neden oluşur ve sonucu nedir?","steps":[{"t":"Kapakçığın normal görevi","a":"Geri kaçışı engeller","d":"Sağlıklı toplardamar kapakçıkları kanın geriye kaçmasını engeller. Böylece kan yalnızca kalbe doğru ilerler."},{"t":"Kapakçık zedelenmesi","a":"Kan geri kaçar","d":"Uzun süre ayakta kalma veya damar duvarının zayıflaması kapakçıkları bozar. Bozulan kapaktan kan geri kaçarak toplardamarda birikir."},{"t":"Varis oluşumu","a":"Damar genişler ve kıvrılır","d":"Biriken kan toplardamarı genişletir ve kıvrımlı hale getirir. Bu genişlemiş, belirgin damarlara varis denir."}],"ans":"Kapakçıkların bozulmasıyla kan geri kaçıp birikir, toplardamar genişleyip kıvrılır ve varis oluşur."},{"q":"Egzersiz sırasında kasların atardamarlarının genişlemesi vücut için neden gereklidir?","steps":[{"t":"Artan ihtiyaç","a":"Kaslar çok oksijen ister","d":"Egzersizde kaslar daha fazla enerji harcar ve çok daha fazla oksijene ihtiyaç duyar. Bu ihtiyacı karşılamak için kaslara daha çok kan gönderilmelidir."},{"t":"Damar genişlemesi","a":"Kan akışı artar","d":"Kasların atardamarları genişleyerek o bölgeye giden kan miktarını artırır. Böylece çalışan kaslara daha bol oksijen ve besin ulaşır."},{"t":"Atık temizliği","a":"Karbondioksit ve atık uzaklaşır","d":"Artan kan akışı aynı zamanda kasta biriken karbondioksit ve atıkları da hızla uzaklaştırır. Bu sayede kaslar daha uzun süre verimli çalışabilir."}],"ans":"Egzersizde kasların damarları genişler, böylece kaslara daha fazla oksijen-besin ulaşır ve atıklar hızla uzaklaştırılır."},{"q":"Nabzın atardamarlarda hissedilip toplardamarlarda hissedilmemesinin nedeni nedir?","steps":[{"t":"Nabzın kaynağı","a":"Kalbin basınç dalgası","d":"Nabız, kalbin her kasılmasında oluşan basınç dalgasının damar duvarında yarattığı genişlemedir. Bu dalga atardamarlara doğrudan iletilir."},{"t":"Atardamarda hissedilme","a":"Basınç yüksek ve dalgalı","d":"Atardamarlar kalbe yakın ve yüksek basınçlı olduğundan basınç dalgası belirgindir. Cilde yakın atardamarlardan bu dalga nabız olarak hissedilir."},{"t":"Toplardamarda yok olma","a":"Dalga sönümlenir","d":"Kan kılcallardan geçerken basınç dalgası tümüyle sönümlenir. Toplardamarlara gelindiğinde basınç düşük ve düzgün olduğundan nabız hissedilmez."}],"ans":"Nabız kalbin basınç dalgasıdır; bu dalga kılcallarda sönümlenir, bu yüzden yalnızca yüksek basınçlı atardamarlarda hissedilir."},{"q":"Dolaşım sisteminde kanın tek yönde akmasını sağlayan yapılar nelerdir?","steps":[{"t":"Kalp kapakçıkları","a":"Kalpte tek yön sağlar","d":"Kalpteki AV kapaklar ve yarım ay kapaklar kanın geri kaçmasını engeller. Böylece kan kulakçıktan karıncığa, karıncıktan atardamara tek yönde akar."},{"t":"Toplardamar kapakçıkları","a":"Venlerde tek yön sağlar","d":"Toplardamarların içindeki kapakçıklar kanın geriye kaçmasını önler. Düşük basınca rağmen kan tek yönde kalbe doğru ilerler."},{"t":"Basınç farkı","a":"Akış yönünü destekler","d":"Atardamardan kılcala, oradan toplardamara doğru azalan basınç da akışı tek yönde tutar. Yapısal kapakçıklar ve basınç farkı birlikte tek yönlü dolaşımı sağlar."}],"ans":"Kalp kapakçıkları, toplardamar kapakçıkları ve atardamardan toplardamara azalan basınç farkı birlikte kanın tek yönde akmasını sağlar."},{"q":"Kanın kılcal damarlarda akış hızının en düşük olması toplam kesit alanıyla nasıl açıklanır?","steps":[{"t":"Akış-kesit ilişkisi","a":"Aynı kan hacmi geçer","d":"Belli bir sürede dolaşımın her bölümünden aynı hacimde kan geçer. Kanın hızı, geçtiği toplam kesit alanına ters orantılıdır."},{"t":"Kılcalların toplam kesiti","a":"Çok geniş","d":"Tek bir kılcal çok dar olsa da kılcalların sayısı milyonlarcadır. Bu yüzden kılcalların toplam kesit alanı atardamar ve toplardamarlardan çok daha geniştir."},{"t":"Hız sonucu","a":"Akış yavaşlar","d":"Geniş toplam kesitten geçen kan yayıldığı için hızı en aza iner. Bu yavaşlık dokularla madde alışverişine zaman tanıdığından işlevseldir."}],"ans":"Aynı kan hacmi geçtiğinden hız toplam kesit alanına ters orantılıdır; kılcalların toplam kesiti en geniş olduğundan kan en yavaş burada akar."}]}},"dolasimYolu":{"lise":{"kolay":[{"q":"Büyük dolaşım kalbin hangi boşluğundan başlar?","steps":[{"t":"Büyük dolaşımın tanımı","a":"Kalp-vücut-kalp","d":"Büyük dolaşım, kanın kalpten vücuda gidip yeniden kalbe dönmesidir. Vücudun tüm organlarına temiz kan ulaştırır."},{"t":"Başlangıç noktası","a":"Sol karıncık","d":"Büyük dolaşım sol karıncıktan aorta pompalanan temiz kanla başlar. Sol karıncık vücudun tamamına kan gönderir."}],"ans":"Sol karıncıktan."},{"q":"Küçük dolaşım kalbin hangi boşluğundan başlar?","steps":[{"t":"Küçük dolaşımın tanımı","a":"Kalp-akciğer-kalp","d":"Küçük dolaşım, kanın kalpten akciğerlere gidip geri dönmesidir. Amacı kirli kanı oksijenle temizlemektir."},{"t":"Başlangıç noktası","a":"Sağ karıncık","d":"Küçük dolaşım sağ karıncıktan akciğer atardamarına pompalanan kirli kanla başlar. Sağ karıncık kanı akciğerlere gönderir."}],"ans":"Sağ karıncıktan."},{"q":"Küçük (akciğer) dolaşımının temel amacı nedir?","steps":[{"t":"Kirli kanın durumu","a":"Oksijence fakir","d":"Vücuttan kalbe dönen kan oksijence fakir, karbondioksitçe zengindir. Bu kanın yeniden kullanılabilmesi için temizlenmesi gerekir."},{"t":"Akciğerde temizlenme","a":"Gaz değişimi","d":"Akciğerlerde kan karbondioksitini bırakıp oksijen alır. Böylece kirli kan temizlenir ve tekrar vücuda gönderilmeye hazır olur."}],"ans":"Kanın akciğerde karbondioksiti bırakıp oksijen alarak temizlenmesi."},{"q":"Büyük (sistemik) dolaşımının temel amacı nedir?","steps":[{"t":"Vücudun ihtiyacı","a":"Tüm dokular beslenmeli","d":"Vücuttaki tüm hücreler oksijen ve besin maddesine ihtiyaç duyar. Ayrıca ürettikleri atıkların uzaklaştırılması gerekir."},{"t":"Büyük dolaşımın işlevi","a":"Madde taşır","d":"Büyük dolaşım, temiz kanı tüm vücuda taşıyarak hücrelere oksijen ve besin ulaştırır. Aynı zamanda atıkları toplayıp kalbe geri getirir."}],"ans":"Tüm vücut dokularına oksijen-besin taşımak ve atıkları toplamak."},{"q":"Vücuttan kalbe dönen kirli kan önce hangi boşluğa gelir?","steps":[{"t":"Geri dönüş yolu","a":"Toplardamarlarla kalbe","d":"Vücuttaki dokulardan toplanan kirli kan ana toplardamarlarla kalbe taşınır. Bu kan oksijence fakirdir."},{"t":"İlk boşluk","a":"Sağ kulakçık","d":"Kirli kan önce sağ kulakçığa dolar. Buradan sağ karıncığa geçerek küçük dolaşıma yönlendirilir."}],"ans":"Sağ kulakçığa."},{"q":"Akciğerlerden temizlenip dönen kan önce hangi boşluğa gelir?","steps":[{"t":"Akciğerden dönüş","a":"Akciğer toplardamarıyla","d":"Akciğerlerde oksijen alan temiz kan, akciğer toplardamarlarıyla kalbe döner. Bu kan oksijence zengindir."},{"t":"İlk boşluk","a":"Sol kulakçık","d":"Temizlenmiş kan önce sol kulakçığa gelir. Buradan sol karıncığa geçerek büyük dolaşıma gönderilir."}],"ans":"Sol kulakçığa."},{"q":"Genel olarak atardamarlar nasıl bir kan taşır?","steps":[{"t":"Atardamarın yönü","a":"Kalpten dışarı","d":"Atardamarlar kanı kalpten alıp dokulara götürür. Çoğunlukla bu kan akciğerde oksijenlenmiş temiz kandır."},{"t":"Taşıdığı kan","a":"Temiz (oksijenli) kan","d":"Bu nedenle atardamarlar genellikle oksijence zengin temiz kan taşır. Akciğer atardamarı bu kuralın istisnasıdır."}],"ans":"Genellikle temiz (oksijence zengin) kan taşır."},{"q":"Genel olarak toplardamarlar nasıl bir kan taşır?","steps":[{"t":"Toplardamarın yönü","a":"Dokulardan kalbe","d":"Toplardamarlar kanı dokulardan toplayıp kalbe getirir. Dokular oksijeni kullandığı için bu kan oksijence fakirdir."},{"t":"Taşıdığı kan","a":"Kirli (karbondioksitli) kan","d":"Bu yüzden toplardamarlar genellikle kirli kan taşır. Akciğer toplardamarı bu kuralın istisnasıdır."}],"ans":"Genellikle kirli (oksijence fakir) kan taşır."},{"q":"Akciğer toplardamarı (pulmoner ven) genel kuralın neden istisnasıdır?","steps":[{"t":"Genel kural","a":"Toplardamar kirli kan taşır","d":"Çoğu toplardamar dokulardan gelen kirli kanı kalbe taşır. Bu yüzden toplardamar deyince kirli kan akla gelir."},{"t":"Pulmoner venin durumu","a":"Temiz kan taşır","d":"Akciğer toplardamarı, akciğerde oksijenlenmiş temiz kanı sol kulakçığa getirir. Toplardamar olmasına rağmen temiz kan taşıdığı için istisnadır."}],"ans":"Akciğer toplardamarı, toplardamar olmasına rağmen temiz (oksijence zengin) kan taşıdığı için istisnadır."},{"q":"İnsanda iki ayrı dolaşım (büyük ve küçük) bulunmasının temel nedeni nedir?","steps":[{"t":"Tek dolaşımın sınırı","a":"Basınç düşerdi","d":"Eğer kan akciğerden geçtikten sonra doğrudan vücuda gitseydi, kılcallarda basınç çok düşerdi. Düşük basınçla kan tüm vücuda yeterince ulaşamazdı."},{"t":"İki dolaşımın avantajı","a":"Kalp iki kez pompalar","d":"İki ayrı dolaşımda kalp, kanı akciğerden döndükten sonra yeniden yüksek basınçla pompalar. Böylece hem akciğer hem vücut yeterli kan alır."}],"ans":"Akciğerden dönen kan tekrar yüksek basınçla pompalandığından tüm vücuda yeterli kan ulaşır; bu yüzden iki ayrı dolaşım vardır."},{"q":"Büyük dolaşımda kan kalpten çıktıktan sonra hangi sırayla ilerler?","steps":[{"t":"Çıkış","a":"Sol karıncık → aort","d":"Temiz kan sol karıncıktan aorta pompalanır. Aort vücudun ana atardamarıdır."},{"t":"Dağılım ve dönüş","a":"Kılcallar → toplardamar → sağ kulakçık","d":"Aort dallanarak kılcal damarlara ulaşır ve dokularla madde alışverişi yapılır. Kirlenen kan toplardamarlarla toplanıp sağ kulakçığa döner."}],"ans":"Sol karıncık → aort → atardamarlar → kılcallar → toplardamarlar → sağ kulakçık."},{"q":"Küçük dolaşımda kan kalpten çıktıktan sonra hangi sırayla ilerler?","steps":[{"t":"Çıkış","a":"Sağ karıncık → akciğer atardamarı","d":"Kirli kan sağ karıncıktan akciğer atardamarına pompalanır. Bu atardamar kanı akciğerlere taşır."},{"t":"Temizlenme ve dönüş","a":"Akciğer kılcalları → akciğer toplardamarı → sol kulakçık","d":"Akciğer kılcallarında kan karbondioksiti bırakıp oksijen alır. Temizlenen kan akciğer toplardamarıyla sol kulakçığa döner."}],"ans":"Sağ karıncık → akciğer atardamarı → akciğer kılcalları → akciğer toplardamarı → sol kulakçık."},{"q":"Temiz kan ile kirli kan arasındaki temel fark nedir?","steps":[{"t":"Temiz kan","a":"Oksijence zengin","d":"Temiz kan oksijen bakımından zengin, karbondioksit bakımından fakirdir. Akciğerde oksijen alarak temizlenir."},{"t":"Kirli kan","a":"Karbondioksitçe zengin","d":"Kirli kan oksijen bakımından fakir, karbondioksit ve atık bakımından zengindir. Dokular oksijeni kullanıp atık verdiği için kan kirlenir."}],"ans":"Temiz kan oksijence zengin, kirli kan ise oksijence fakir ve karbondioksitçe zengindir."},{"q":"Sindirim sisteminden emilen besinler hangi dolaşım sayesinde tüm vücuda dağılır?","steps":[{"t":"Besinlerin emilimi","a":"Bağırsaktan kana geçer","d":"Sindirilen besinler ince bağırsak kılcallarından kana emilir. Bu besinlerin tüm hücrelere ulaşması gerekir."},{"t":"Dağıtan dolaşım","a":"Büyük dolaşım","d":"Besince zenginleşen kan büyük dolaşım yoluyla tüm vücuda dağıtılır. Böylece her hücre ihtiyacı olan besine kavuşur."}],"ans":"Büyük (sistemik) dolaşım sayesinde."},{"q":"Kalbin sağ tarafı ile sol tarafının taşıdığı kan açısından farkı nedir?","steps":[{"t":"Sağ taraf","a":"Kirli kan","d":"Kalbin sağ kulakçığı ve sağ karıncığı vücuttan dönen kirli kanı taşır. Bu kan akciğerlere pompalanmak üzere sağ tarafta bulunur."},{"t":"Sol taraf","a":"Temiz kan","d":"Kalbin sol kulakçığı ve sol karıncığı akciğerden gelen temiz kanı taşır. Bu kan vücuda pompalanmak üzere sol tarafta bulunur."}],"ans":"Sağ taraf kirli (oksijence fakir), sol taraf temiz (oksijence zengin) kan taşır."}],"zor":[{"q":"İnsanda çift (ikili) dolaşımın tek dolaşıma göre üstünlüğünü mekanizmayla açıklayınız.","steps":[{"t":"Tek dolaşımın sorunu","a":"Basınç akciğerde tükenir","d":"Tek dolaşımlı sistemde kan, kalpten çıkıp akciğer kılcallarından geçtikten sonra basıncını büyük ölçüde kaybeder. Düşük basınçlı kan vücut dokularına yavaş ve yetersiz ulaşır."},{"t":"Çift dolaşımda yeniden pompalama","a":"Kalp iki kez basınç verir","d":"Çift dolaşımda akciğerden dönen kan tekrar kalbe gelir ve sol karıncıkta yeniden yüksek basınçla pompalanır. Böylece vücuda giden kan yüksek basınçlı ve hızlı olur."},{"t":"Metabolik üstünlük","a":"Hızlı madde taşıma","d":"Yüksek basınçlı hızlı dolaşım, hızlı metabolizmaya sahip memelilerin oksijen ihtiyacını karşılar. Bu nedenle çift dolaşım daha yüksek enerji üretimine olanak tanır."}],"ans":"Çift dolaşımda akciğerden dönen kan yeniden yüksek basınçla pompalandığından vücuda hızlı ve bol kan ulaşır; bu yüksek metabolizmayı destekler."},{"q":"Karaciğer kapı (portal) dolaşımı nedir ve hangi açıdan özeldir?","steps":[{"t":"Tanım","a":"İki kılcal yatak arası dolaşım","d":"Kapı dolaşımı, kanın bir kılcal yataktan diğer kılcal yatağa toplardamar aracılığıyla taşınmasıdır. Karaciğer kapı dolaşımı bunun en bilinen örneğidir."},{"t":"Yol izleyişi","a":"Bağırsak → karaciğer","d":"Sindirim kanalından emilen besince zengin kan, kapı toplardamarıyla doğrudan karaciğere taşınır. Karaciğer bu kanı işleyip düzenler."},{"t":"Özelliği","a":"Toplardamar iki kılcalı birleştirir","d":"Normalde toplardamar kanı doğrudan kalbe götürürken, burada kanı önce karaciğer kılcallarına götürür. Bu, besinlerin kana karışmadan önce karaciğerde denetlenmesini sağlar."}],"ans":"Kapı dolaşımı, kanın bir kılcal yataktan diğerine (bağırsaktan karaciğere) toplardamarla taşınmasıdır; besinlerin önce karaciğerde işlenmesini sağladığı için özeldir."},{"q":"Büyük ve küçük dolaşımı tam bir döngü olarak adım adım sıralayınız.","steps":[{"t":"Büyük dolaşım","a":"Sol karıncık → vücut → sağ kulakçık","d":"Temiz kan sol karıncıktan aorta pompalanır, vücut dokularına dağılır ve madde alışverişi yapılır. Kirlenen kan toplardamarlarla sağ kulakçığa döner."},{"t":"Sağdan akciğere","a":"Sağ kulakçık → sağ karıncık → akciğer","d":"Sağ kulakçıktaki kirli kan sağ karıncığa geçer. Sağ karıncık bu kanı akciğer atardamarıyla akciğerlere pompalar."},{"t":"Küçük dolaşım dönüşü","a":"Akciğer → sol kulakçık → sol karıncık","d":"Akciğerde temizlenen kan akciğer toplardamarıyla sol kulakçığa, oradan sol karıncığa geçer. Böylece kan yeniden büyük dolaşıma hazır hale gelir ve döngü tamamlanır."}],"ans":"Sol karıncık → vücut → sağ kulakçık → sağ karıncık → akciğer → sol kulakçık → sol karıncık şeklinde tam döngü tamamlanır."},{"q":"Anne karnındaki bebekte (fetüste) akciğer dolaşımının büyük ölçüde devre dışı olmasının nedeni nedir?","steps":[{"t":"Fetüsün oksijen kaynağı","a":"Plasenta","d":"Anne karnındaki bebek oksijeni akciğerlerinden değil, plasenta yoluyla anneden alır. Bu nedenle fetüsün akciğerleri henüz solunum yapmaz."},{"t":"Kanın yönlendirilmesi","a":"Akciğer atlanır","d":"Fetüste kanın büyük kısmı akciğerleri atlayacak şekilde özel açıklıklardan (örneğin kalpte foramen ovale) geçer. Böylece kan büyük ölçüde akciğerlere uğramadan dolaşır."},{"t":"Doğumla değişim","a":"Akciğer devreye girer","d":"Doğumdan sonra bebek nefes almaya başlayınca akciğer dolaşımı tam olarak devreye girer. Kalpteki özel açıklıklar kapanır ve normal çift dolaşım kurulur."}],"ans":"Fetüs oksijeni plasentadan aldığı için akciğerleri çalışmaz; kan özel açıklıklardan akciğeri atlar, doğumda akciğer dolaşımı tam devreye girer."},{"q":"Akciğer atardamarının kirli, akciğer toplardamarının temiz kan taşıması neden tutarlıdır?","steps":[{"t":"Damar tanımının temeli","a":"Yön belirler, içerik değil","d":"Atardamar kanı kalpten dışarı, toplardamar kanı kalbe taşıyan damardır. Damar adı taşıdığı kanın temiz veya kirli olmasına göre değil, akış yönüne göre verilir."},{"t":"Akciğer atardamarı","a":"Kirli kanı dışa taşır","d":"Akciğer atardamarı sağ karıncıktan çıkıp kirli kanı akciğere götürür. Kalpten dışarı taşıdığı için atardamardır, kirli kan taşıması tanımla çelişmez."},{"t":"Akciğer toplardamarı","a":"Temiz kanı kalbe taşır","d":"Akciğer toplardamarı temizlenmiş kanı akciğerden kalbe getirir. Kanı kalbe taşıdığı için toplardamardır, temiz kan taşıması tutarlıdır."}],"ans":"Damar adı akış yönüne göre verildiğinden, kalpten çıkan akciğer atardamarı kirli, kalbe gelen akciğer toplardamarı temiz kan taşır; bu tanımla tutarlıdır."},{"q":"Kalpte septum (perde) doğuştan delik olursa dolaşımda ne tür bir bozukluk oluşur?","steps":[{"t":"Septumun görevi","a":"Temiz-kirli ayrımı","d":"Septum, kalbin temiz kan taşıyan sol tarafı ile kirli kan taşıyan sağ tarafını birbirinden ayırır. Bu ayrım sayesinde vücuda hep temiz kan gider."},{"t":"Deliğin etkisi","a":"Kan karışır","d":"Septumda bir delik varsa temiz ve kirli kan birbirine karışır. Vücuda giden kanın oksijen miktarı azalır."},{"t":"Sonuç","a":"Dokular yetersiz oksijen alır","d":"Oksijeni azalmış kan dokuları yeterince besleyemez ve kalp telafi için fazla çalışır. Bu durum çocuğun gelişimini ve enerjisini olumsuz etkiler."}],"ans":"Septum deliğinde temiz ve kirli kan karışır, vücuda giden oksijen azalır ve kalp fazladan çalışmak zorunda kalır."},{"q":"Büyük dolaşımın küçük dolaşıma göre daha yüksek basınç gerektirmesinin nedeni nedir?","steps":[{"t":"Yol uzunluğu","a":"Vücut çok geniş bir ağ","d":"Büyük dolaşım kanı tüm vücuda, baştan ayağa kadar ulaştırır. Bu uzun ve geniş damar ağı kanın akışına büyük direnç gösterir."},{"t":"Küçük dolaşımın yolu","a":"Yalnızca akciğer","d":"Küçük dolaşım kanı sadece yakındaki akciğerlere taşır. Yol kısa ve direnç düşük olduğu için az basınç yeterlidir."},{"t":"Basınç farkı","a":"Sol karıncık daha güçlü","d":"Daha uzun yola ve yüksek dirence karşı pompalayan sol karıncık daha güçlüdür ve yüksek basınç üretir. Bu yüzden büyük dolaşım basıncı, küçük dolaşımdan belirgin biçimde yüksektir."}],"ans":"Büyük dolaşım tüm vücudu kapsayan uzun ve dirençli bir yol olduğundan, sol karıncık küçük dolaşımdan çok daha yüksek basınç üretir."},{"q":"Akciğerde gerçekleşen gaz değişimi sonucu kanın bileşimi nasıl değişir?","steps":[{"t":"Akciğere gelen kan","a":"Kirli kan","d":"Sağ karıncıktan akciğere gelen kan karbondioksit bakımından zengin, oksijen bakımından fakirdir. Bu kanın temizlenmesi gerekir."},{"t":"Difüzyonla gaz değişimi","a":"Oksijen girer, CO2 çıkar","d":"Akciğer kılcalları ile hava keseleri arasında difüzyonla gaz alışverişi olur. Oksijen kana geçer, karbondioksit kandan hava keselerine geçerek dışarı atılır."},{"t":"Akciğerden çıkan kan","a":"Temiz kan","d":"Bu değişim sonunda kan oksijence zenginleşir, karbondioksiti azalır. Temizlenen bu kan sol kulakçığa dönerek vücuda gönderilmeye hazır olur."}],"ans":"Akciğerde oksijen kana geçer, karbondioksit kandan atılır; böylece kirli kan oksijence zengin temiz kana dönüşür."},{"q":"Doku hücrelerinin çevresindeki kılcallarda büyük dolaşım sırasında hangi alışveriş gerçekleşir?","steps":[{"t":"Kılcala gelen kan","a":"Oksijen ve besin zengini","d":"Büyük dolaşımda dokulara ulaşan kan oksijen ve besin maddeleri bakımından zengindir. Hücreler yaşamak için bunlara ihtiyaç duyar."},{"t":"Alışveriş yönü","a":"İki yönlü difüzyon","d":"Oksijen ve besinler kandan hücrelere geçerken, karbondioksit ve atıklar hücrelerden kana geçer. Bu alışveriş kılcalların ince duvarından difüzyonla olur."},{"t":"Kılcaldan ayrılan kan","a":"Atıkça zengin kirli kan","d":"Alışveriş sonucu kan oksijenini bırakmış, atıkları almıştır. Kirlenen bu kan toplardamarlarla kalbe geri taşınır."}],"ans":"Kılcallarda oksijen ve besin kandan hücrelere, karbondioksit ve atıklar hücrelerden kana geçer; böylece kan kirlenir."},{"q":"Egzersizde hem büyük hem küçük dolaşımın hızlanması neden eş zamanlı olur?","steps":[{"t":"Artan oksijen ihtiyacı","a":"Kaslar daha çok oksijen ister","d":"Egzersizde çalışan kaslar çok daha fazla oksijen ve besin gerektirir. Bu ihtiyacı karşılamak için büyük dolaşım hızlanır."},{"t":"Kanın temizlenme ihtiyacı","a":"CO2 artar","d":"Hızlı metabolizma fazla karbondioksit üretir, kanın daha sık temizlenmesi gerekir. Bu yüzden kanın akciğere gidişi, yani küçük dolaşım da hızlanmalıdır."},{"t":"Tek pompayla eş zamanlılık","a":"Kalp hızı her ikisini birden artırır","d":"Her iki dolaşım da aynı kalbin farklı taraflarınca sürdürülür. Kalp daha hızlı atınca hem büyük hem küçük dolaşım birlikte hızlanır."}],"ans":"Her iki dolaşım da aynı kalp tarafından sürdürüldüğünden, kalp hızı arttığında büyük ve küçük dolaşım eş zamanlı hızlanır."},{"q":"Kapı (portal) dolaşımının vücut için sağladığı temel yarar nedir?","steps":[{"t":"Bağırsaktan emilen kan","a":"Besin ve zararlı madde içerebilir","d":"Sindirim kanalından emilen kan, besinlerin yanı sıra zararlı maddeleri de içerebilir. Bu kanın doğrudan tüm vücuda yayılması riskli olurdu."},{"t":"Karaciğerde denetim","a":"İşleme ve arıtma","d":"Kapı dolaşımı bu kanı önce karaciğere götürür. Karaciğer besinleri depolar veya işler, zararlı maddeleri etkisizleştirir."},{"t":"Sonuç","a":"Düzenlenmiş kan vücuda gider","d":"Karaciğerden geçen kanın bileşimi düzenlenmiş ve arıtılmış olur. Böylece vücuda dengeli ve güvenli bir kan ulaşır."}],"ans":"Kapı dolaşımı, bağırsaktan gelen besin yüklü kanı önce karaciğere götürerek besinlerin işlenmesini ve zararlı maddelerin arıtılmasını sağlar."},{"q":"Kalbin sol tarafının sağ tarafından daha güçlü olması hangi dolaşımla ilişkilidir?","steps":[{"t":"Sol tarafın görevi","a":"Büyük dolaşımı sürdürür","d":"Kalbin sol tarafı büyük dolaşımdan sorumludur ve kanı tüm vücuda pompalar. Bu uzun yol yüksek basınç gerektirir."},{"t":"Sağ tarafın görevi","a":"Küçük dolaşımı sürdürür","d":"Sağ taraf yalnızca akciğerlere kan gönderen küçük dolaşımı yürütür. Bu kısa yol düşük basınçla halledilir."},{"t":"Güç farkının nedeni","a":"Büyük dolaşım yüksek basınç ister","d":"Büyük dolaşımdaki yüksek basınç ihtiyacı sol karıncığın daha kalın ve güçlü olmasını gerektirir. Bu yüzden sol taraf sağ taraftan belirgin biçimde güçlüdür."}],"ans":"Sol taraf yüksek basınç gerektiren büyük dolaşımı sürdürdüğünden, küçük dolaşımı yürüten sağ taraftan daha güçlüdür."},{"q":"Kanın bir tam turunu hem oksijen seviyesi hem de basınç değişimi açısından değerlendiriniz.","steps":[{"t":"Sol karıncıktan çıkış","a":"Yüksek oksijen, yüksek basınç","d":"Kan sol karıncıktan aorta yüksek basınçla pompalanır ve oksijence zengindir. Vücuda doğru ilerlerken hem basınç hem oksijen yüksektir."},{"t":"Doku kılcallarından sonra","a":"Düşük oksijen, düşük basınç","d":"Doku kılcallarında oksijen bırakılıp atık alındığından kan oksijence fakirleşir. Aynı zamanda sürtünme nedeniyle basınç da düşer."},{"t":"Akciğerden dönüş","a":"Oksijen yükselir, basınç tekrar artar","d":"Akciğerde kan yeniden oksijen alır ve sol kulakçığa döner. Sol karıncıkta tekrar pompalanınca basınç da yükselir ve döngü baştan başlar."}],"ans":"Kan turda oksijeni dokuda bırakıp akciğerde geri alır; basınç ise sol karıncıkta yüksekken yol boyunca düşer ve her pompalamada yeniden yükselir."},{"q":"İnsanın aktif ve yüksek enerjili bir canlı olmasında çift dolaşımın rolü nedir?","steps":[{"t":"Yüksek enerji ihtiyacı","a":"Bol oksijen gerekir","d":"İnsan gibi sıcakkanlı, aktif canlılar yüksek bir metabolizma hızına sahiptir. Bu hız sürekli ve bol oksijen sağlanmasını gerektirir."},{"t":"Çift dolaşımın katkısı","a":"Temiz-kirli kan ayrı kalır","d":"Çift dolaşımda temiz ve kirli kan karışmaz, vücuda her zaman tam oksijenli kan gider. Ayrıca yeniden pompalama sayesinde kan hızlı dolaşır."},{"t":"Sonuç","a":"Yüksek metabolizma desteklenir","d":"Yüksek oksijen taşıma verimi, hücrelerin sürekli bol enerji üretmesini sağlar. Bu da insanın aktif ve yüksek enerjili yaşamını mümkün kılar."}],"ans":"Çift dolaşım, temiz-kirli kanı ayrı tutarak ve kanı hızlı dolaştırarak yüksek oksijen verimi sağlar; bu da insanın yüksek metabolizmasını ve aktif yaşamını destekler."},{"q":"Akciğer dolaşımının düşük basınçlı olması akciğerler için neden önemlidir?","steps":[{"t":"Akciğer kılcallarının yapısı","a":"Çok ince ve narin","d":"Akciğerlerdeki kılcal damarlar hava keselerinin çevresinde çok ince ve narin bir yapı oluşturur. Yüksek basınç bu narin yapılara zarar verirdi."},{"t":"Düşük basıncın yararı","a":"Sıvı sızması önlenir","d":"Küçük dolaşım düşük basınçlı olduğundan kılcallardan hava keselerine sıvı sızması engellenir. Eğer basınç yüksek olsaydı keselere sıvı dolar ve solunum bozulurdu."},{"t":"Gaz değişimi için uygunluk","a":"Sağlıklı solunum","d":"Düşük basınç sayesinde hava keseleri kuru ve gaz değişimine uygun kalır. Bu, akciğerlerin verimli çalışmasını ve sağlıklı solunumu sağlar."}],"ans":"Akciğer dolaşımının düşük basıncı, narin kılcallardan hava keselerine sıvı sızmasını önler ve gaz değişimini sağlıklı tutar."}]}},"uyariSistemi":{"lise":{"kolay":[{"q":"Kalbin uyarıyı başlatan ve doğal pil görevi gören yapısı hangisidir?","steps":[{"t":"Uyarının kaynağı","a":"Kalp kendi uyarısını üretir","d":"Kalp, çalışması için dışarıdan emir beklemez, kendi içinde uyarı üretir. Bu uyarıyı başlatan özel bir bölge bulunur."},{"t":"Yapının adı","a":"SA düğümü","d":"Bu yapıya sinoatriyal (SA) düğüm denir ve sağ kulakçıkta bulunur. Kalbin doğal pili olarak atış ritmini başlatır."}],"ans":"SA (sinoatriyal) düğümü."},{"q":"SA düğümünden çıkan uyarı bir sonraki olarak hangi yapıya ulaşır?","steps":[{"t":"Uyarının yayılması","a":"Kulakçıklara yayılır","d":"SA düğümünden çıkan uyarı önce kulakçıkları kasarak ilerler. Ardından bir aktarma noktasına ulaşır."},{"t":"İkinci durak","a":"AV düğümü","d":"Uyarı, kulakçık ile karıncık sınırındaki atriyoventriküler (AV) düğüme ulaşır. AV düğümü uyarıyı karıncıklara iletecek bir sonraki merkezdir."}],"ans":"AV (atriyoventriküler) düğümüne."},{"q":"Kalbin uyarı-iletim sisteminde AV düğümünden sonra uyarı hangi yapıdan geçer?","steps":[{"t":"AV düğümden sonrası","a":"Karıncıklara doğru","d":"AV düğümünden çıkan uyarının karıncıklara iletilmesi gerekir. Bunun için özel iletim lifleri kullanılır."},{"t":"İletim yolu","a":"His demeti","d":"Uyarı önce His demeti (atriyoventriküler demet) boyunca ilerler. Bu demet uyarıyı karıncıkların derinlerine taşır."}],"ans":"His demetinden (AV demeti)."},{"q":"His demetinden sonra uyarıyı karıncık kas hücrelerine yayan lifler hangisidir?","steps":[{"t":"Son iletim aşaması","a":"Karıncık kasına yayılma","d":"His demetinden gelen uyarının tüm karıncık kasına dağılması gerekir. Bunu sağlayan ince dallanmış lifler vardır."},{"t":"Liflerin adı","a":"Purkinje lifleri","d":"Bu liflere Purkinje lifleri denir ve karıncık duvarlarına yayılır. Uyarıyı hızla ileterek karıncıkların aynı anda kasılmasını sağlar."}],"ans":"Purkinje lifleri."},{"q":"Kalbin sinirsel uyarı olmadan kendiliğinden atabilmesine ne ad verilir?","steps":[{"t":"Kalbin bağımsızlığı","a":"Dış emir gerekmez","d":"Kalp, beyinden gelen sinir emri olmasa bile kendi başına atmaya devam edebilir. Bu, kalp kasının özel bir özelliğidir."},{"t":"Özelliğin adı","a":"Otomatik (otoritmik) çalışma","d":"Kalbin kendi uyarısını üretip kendiliğinden atmasına otomatizm (otoritmiklik) denir. Bu sayede vücuttan koparılmış bir kalp bile bir süre atabilir."}],"ans":"Otomatik (otoritmik) çalışma / kalp otomatizmi."},{"q":"Kalbin uyarı sisteminde SA düğümünün konumu neresidir?","steps":[{"t":"Doğal pilin yeri","a":"Kalbin sağ üst bölgesi","d":"SA düğümü, kalbin doğal pili olduğu için uyarı buradan başlar. Bu nedenle kulakçık bölgesinde yer alır."},{"t":"Tam konumu","a":"Sağ kulakçık duvarında","d":"SA düğümü sağ kulakçığın üst duvarında bulunur. Buradan başlayan uyarı önce kulakçıklara yayılır."}],"ans":"Sağ kulakçığın üst duvarında."},{"q":"Kalbin uyarı sisteminde uyarının izlediği sıra nasıldır?","steps":[{"t":"Başlangıç ve yayılma","a":"SA → kulakçıklar → AV","d":"Uyarı SA düğümünde başlar, kulakçıkları kasarak AV düğüme ulaşır. AV düğüm uyarıyı karıncıklara aktaran köprüdür."},{"t":"Karıncıklara iletim","a":"His → Purkinje","d":"AV düğümünden sonra uyarı His demetiyle ilerler ve Purkinje lifleriyle karıncık kasına yayılır. Böylece karıncıklar kasılır."}],"ans":"SA düğümü → AV düğümü → His demeti → Purkinje lifleri."},{"q":"Kalp hızının artması veya azalması hangi sistem tarafından düzenlenir?","steps":[{"t":"Otomatik çalışma ve düzenleme","a":"Kalp kendi atar ama hız ayarlanır","d":"Kalp uyarısını kendi üretir, fakat atış hızı vücudun ihtiyacına göre değişmelidir. Bu hızı dışarıdan düzenleyen bir sistem vardır."},{"t":"Düzenleyen sistem","a":"Otonom sinir sistemi ve hormonlar","d":"Kalp hızı, isteğimiz dışında çalışan otonom sinir sistemi ve bazı hormonlarla düzenlenir. Bu sistem SA düğümünün hızını artırıp azaltır."}],"ans":"Otonom sinir sistemi ve hormonlar."},{"q":"Heyecanlanınca veya korkunca kalbin hızlanmasını sağlayan hormon hangisidir?","steps":[{"t":"Durumun gereği","a":"Vücut tetikte olmalı","d":"Korku veya heyecan anında vücut hızlı tepki verecek duruma geçer. Bu durumda kalbin daha hızlı atması gerekir."},{"t":"Etkili hormon","a":"Adrenalin","d":"Böbreküstü bezinden salgılanan adrenalin hormonu SA düğümünü uyararak kalp hızını artırır. Böylece kaslara ve organlara daha fazla kan gönderilir."}],"ans":"Adrenalin."},{"q":"Kalbin SA düğümünün diğer yapılara göre daha hızlı uyarı üretmesi neyi belirler?","steps":[{"t":"En hızlı uyarı kaynağı","a":"SA düğümü baskındır","d":"Kalpteki birçok yapı uyarı üretebilir, ancak SA düğümü en hızlı uyarıyı üretir. En hızlı üreten yapı tüm kalbe ritmi dayatır."},{"t":"Sonuç","a":"Kalp hızını SA belirler","d":"Bu yüzden kalbin normal atış hızını SA düğümü belirler. Diğer yapılar onun ritmine uyarak kasılır."}],"ans":"SA düğümü en hızlı uyarı ürettiği için kalbin normal atış hızını (ritmini) belirler."},{"q":"AV düğümünde uyarının kısa süre gecikmesinin yararı nedir?","steps":[{"t":"Gecikme noktası","a":"AV düğümü uyarıyı yavaşlatır","d":"AV düğümü, kendisine gelen uyarıyı karıncıklara iletmeden önce kısa süre geciktirir. Bu gecikme bilinçli olarak sistemin bir parçasıdır."},{"t":"Gecikmenin yararı","a":"Kulakçıklar önce boşalır","d":"Bu kısa gecikme sayesinde kulakçıklar kasılıp kanı karıncıklara tam boşaltır. Ardından karıncıklar kasılır, böylece pompalama verimli olur."}],"ans":"Gecikme, kulakçıkların kanı karıncığa tam boşaltmasına zaman tanıyarak verimli pompalamayı sağlar."},{"q":"Dinlenme anında kalp hızını yavaşlatan otonom sinir hangisidir?","steps":[{"t":"Dinlenme durumu","a":"Kalp yavaşlamalı","d":"Dinlenirken vücudun oksijen ihtiyacı azalır ve kalbin yavaş atması yeterlidir. Bu durumu sağlayan bir sinir kolu vardır."},{"t":"Etkili sinir","a":"Parasempatik sinir (vagus)","d":"Parasempatik sistemin vagus siniri SA düğümünü baskılayarak kalp hızını düşürür. Böylece dinlenmede kalp daha yavaş ve ekonomik çalışır."}],"ans":"Parasempatik sinir (vagus siniri)."},{"q":"Egzersiz sırasında kalp hızını artıran otonom sinir hangisidir?","steps":[{"t":"Egzersiz durumu","a":"Kalp hızlanmalı","d":"Egzersizde kaslar daha çok oksijen ister ve kalbin hızlanması gerekir. Bunu sağlayan bir sinir kolu devreye girer."},{"t":"Etkili sinir","a":"Sempatik sinir","d":"Sempatik sinir SA düğümünü uyararak kalp hızını ve kasılma gücünü artırır. Böylece dokulara daha fazla kan pompalanır."}],"ans":"Sempatik sinir."},{"q":"Kalbin uyarı-iletim sistemindeki yapılar hangi tür dokudan oluşur?","steps":[{"t":"Sistemin özelliği","a":"Hem ileti hem kasılma","d":"Uyarı sistemi yapıları sinir gibi davranıp uyarıyı iletir, ancak sinir hücresi değildir. Bu yapılar kalbin kendi dokusundan köken alır."},{"t":"Doku türü","a":"Özelleşmiş kalp kası","d":"SA düğümü, AV düğümü, His demeti ve Purkinje lifleri özelleşmiş kalp kası hücrelerinden oluşur. Bu hücreler uyarı üretme ve hızlı iletme yeteneği kazanmıştır."}],"ans":"Özelleşmiş kalp kası hücrelerinden (sinir değil)."},{"q":"Kalp uyarı sistemi sayesinde kulakçıklar ve karıncıkların kasılma sırası nasıldır?","steps":[{"t":"İlk kasılan","a":"Kulakçıklar","d":"SA düğümünden çıkan uyarı önce kulakçıklara yayılır ve onları kasar. Böylece kan karıncıklara dolar."},{"t":"Sonra kasılan","a":"Karıncıklar","d":"Uyarı AV düğüm, His demeti ve Purkinje lifleriyle karıncıklara ulaşınca karıncıklar kasılır. Bu sıralı kasılma kanın doğru yönde pompalanmasını sağlar."}],"ans":"Önce kulakçıklar, ardından karıncıklar kasılır."}],"zor":[{"q":"Kalbin uyarı-iletim sistemini, uyarının izlediği yolu ve her yapının görevini açıklayınız.","steps":[{"t":"Başlatıcı: SA düğümü","a":"Ritmi başlatır","d":"Sağ kulakçıktaki SA düğümü kalbin doğal pilidir ve uyarıyı başlatır. Buradan çıkan uyarı kulakçıkları kasarak ilerler."},{"t":"Aktarıcı: AV düğümü","a":"Uyarıyı geciktirir ve iletir","d":"AV düğümü kulakçık-karıncık sınırında uyarıyı kısa süre geciktirerek karıncıklara aktarır. Bu gecikme kulakçıkların önce boşalmasını sağlar."},{"t":"İletici: His ve Purkinje","a":"Karıncıklara hızlı yayar","d":"Uyarı His demetiyle karıncık derinlerine inip Purkinje lifleriyle tüm karıncık kasına yayılır. Bu hızlı iletim karıncıkların eş zamanlı ve güçlü kasılmasını sağlar."}],"ans":"SA düğümü uyarıyı başlatır, AV düğümü geciktirip iletir, His demeti ve Purkinje lifleri uyarıyı karıncıklara yayarak güçlü kasılmayı sağlar."},{"q":"Vücudundan ayrılmış (uygun ortamda tutulan) bir kalbin bir süre atmaya devam etmesi neyi kanıtlar?","steps":[{"t":"Gözlem","a":"Kalp dışarıda atıyor","d":"Uygun sıcaklık ve besin ortamında tutulan, vücuttan ayrılmış bir kalp bir süre kendiliğinden atmaya devam eder. Bu, kalbe hiçbir sinir bağlı olmadan gerçekleşir."},{"t":"Anlamı","a":"Uyarı kalbin içinde üretilir","d":"Kalp dışarıdan emir almadan attığına göre uyarı kalbin kendi içinde üretiliyordur. Bu uyarıyı SA düğümü üretir."},{"t":"Kanıtladığı özellik","a":"Kalp otomatizmi","d":"Bu gözlem kalbin otomatik (otoritmik) çalıştığını kanıtlar. Sinirler yalnızca hızı ayarlar, atışı başlatan kalbin kendisidir."}],"ans":"Kalbin sinirlerden bağımsız atması, uyarının kalbin kendi içinde (SA düğümünde) üretildiğini, yani kalp otomatizmini kanıtlar."},{"q":"AV düğümündeki gecikmenin kaybolması (çok hızlı iletim) pompalama verimini nasıl bozar?","steps":[{"t":"Normal gecikmenin rolü","a":"Sıralı kasılma sağlar","d":"AV düğümündeki gecikme, kulakçıklar kasılıp karıncıkları doldurduktan sonra karıncıkların kasılmasını sağlar. Bu sıralama pompalama verimi için gereklidir."},{"t":"Gecikme kaybolursa","a":"Eş zamanlı kasılma","d":"Gecikme olmazsa kulakçık ve karıncıklar neredeyse aynı anda kasılır. Karıncıklar henüz dolmadan kasılmaya başlar."},{"t":"Sonuç","a":"Pompalanan kan azalır","d":"Yeterince dolmamış karıncıklar az kan pompalar, dolaşım verimi düşer. Bu yüzden AV gecikmesi kalbin etkili çalışması için zorunludur."}],"ans":"Gecikme kaybolursa karıncıklar dolmadan kasılır, az kan pompalanır ve dolaşım verimi düşer; bu yüzden AV gecikmesi zorunludur."},{"q":"SA düğümü zarar görürse kalbin atmaya devam etmesini ne sağlar?","steps":[{"t":"SA düğümün kaybı","a":"Asıl pil devre dışı","d":"SA düğümü kalbin normal pilidir ve zarar görürse uyarı başlatamaz. Ancak kalbin tümüyle durması beklenmez."},{"t":"Yedek pil","a":"AV düğümü devreye girer","d":"SA düğümü çalışmazsa AV düğümü kendi yavaş uyarısını üreterek kalbi atmaya devam ettirir. AV düğümü ikincil bir pil görevi görür."},{"t":"Sonuç","a":"Daha yavaş ritim","d":"AV düğümünün ürettiği ritim SA düğümünkinden daha yavaştır. Bu yüzden kalp atar ama hızı normalden düşük olur."}],"ans":"SA düğümü zarar görürse AV düğümü yedek pil olarak devreye girer; kalp atmaya devam eder ama daha yavaş bir ritimle."},{"q":"Otonom sinir sisteminin sempatik ve parasempatik bölümleri kalp hızını nasıl zıt yönde etkiler?","steps":[{"t":"Sempatik etki","a":"Hızlandırır","d":"Sempatik sinir, stres ve egzersiz gibi durumlarda SA düğümünü uyararak kalp hızını ve kasılma gücünü artırır. Böylece dokulara daha çok kan gider."},{"t":"Parasempatik etki","a":"Yavaşlatır","d":"Parasempatik sinir (vagus), dinlenme durumunda SA düğümünü baskılayarak kalp hızını düşürür. Bu, enerji tasarrufu sağlar."},{"t":"Denge","a":"İhtiyaca göre ayarlanır","d":"İki sistem zıt yönde çalışarak kalp hızını vücudun anlık ihtiyacına göre dengeler. Böylece kalp hem hızlanabilir hem yavaşlayabilir."}],"ans":"Sempatik sinir kalbi hızlandırır, parasempatik sinir yavaşlatır; ikisi zıt yönde çalışarak kalp hızını vücudun ihtiyacına göre dengeler."},{"q":"Kalbin uyarı sistemi yapıları neden sinir hücresi değil de özelleşmiş kas hücresidir, bu nasıl bir avantaj sağlar?","steps":[{"t":"Köken","a":"Kalp kasından gelişir","d":"SA, AV düğümleri ve iletim lifleri sinir değil, özelleşmiş kalp kası hücrelerinden oluşur. Bu hücreler kasılma yeteneğini büyük ölçüde uyarı iletme yeteneğiyle değiştirmiştir."},{"t":"Kasla bütünleşme","a":"Doğrudan kas içinde","d":"Bu yapılar kalp kasının içinde yer aldığı için uyarıyı doğrudan kas hücrelerine aktarır. Aradaki bağlantılar (ara diskler) uyarının hızlı yayılmasını sağlar."},{"t":"Avantaj","a":"Bağımsız ve eş zamanlı kasılma","d":"Bu yapı sayesinde kalp dışarıdan sinire gerek kalmadan kendi ritmini üretir. Ayrıca uyarı tüm kasa hızla yayıldığı için karıncıklar bir bütün halinde eş zamanlı kasılır."}],"ans":"Uyarı yapıları özelleşmiş kalp kasından oluştuğu için kalp dışarıdan sinire bağımlı olmadan kendi ritmini üretir ve uyarı kasa hızlıca yayılarak eş zamanlı kasılma sağlanır."},{"q":"Uyarının karıncıklarda aşağıdan (uçtan) yukarıya doğru yayılmaya başlaması neden işlevseldir?","steps":[{"t":"Purkinje yayılımı","a":"Önce karıncık tabanına ulaşır","d":"His demeti ve Purkinje lifleri uyarıyı önce karıncıkların alt ucuna (tepe noktasına) iletir. Kasılma buradan başlar."},{"t":"Kasılma yönü","a":"Aşağıdan yukarı sıkma","d":"Karıncıklar alttan yukarıya doğru kasılarak kanı yukarıdaki damar çıkışlarına doğru iter. Bu, diş macunu tüpünü alttan sıkmaya benzer."},{"t":"İşlevsel sonuç","a":"Kan etkili boşaltılır","d":"Bu yönlü kasılma kanın karıncıktan damarlara verimli biçimde pompalanmasını sağlar. Yukarıdan başlasaydı kan damar çıkışına etkili itilemezdi."}],"ans":"Uyarı önce karıncık ucuna ulaşıp kasılmayı alttan başlattığından, kan yukarıdaki damar çıkışlarına etkili biçimde pompalanır."},{"q":"Kalp hızının uzun süre çok yüksek seyretmesi pompalama verimini nasıl düşürebilir?","steps":[{"t":"Hız ve dolum süresi","a":"Diyastol kısalır","d":"Kalp çok hızlı atınca her döngüdeki gevşeme (diyastol) süresi kısalır. Karıncıkların kanla dolması için yeterli zaman kalmaz."},{"t":"Az dolum","a":"Atış başına az kan","d":"Yeterince dolamayan karıncıklar her atışta daha az kan pompalar. Hız artsa bile atış başına pompalanan kan azaldığından verim düşer."},{"t":"Beslenme sorunu","a":"Kalbin kendisi de yetersiz beslenir","d":"Diyastol kısaldığında koroner damarların kalbi beslemesi de zorlaşır. Böylece çok hızlı atan kalp hem az pompalar hem de kendisi yorulur."}],"ans":"Çok yüksek hızda diyastol kısalır, karıncıklar yeterince dolamaz ve atış başına az kan pompalanır; ayrıca kalp kendisi de yeterince beslenemez, böylece verim düşer."},{"q":"EKG (elektrokardiyogram) ile kalbin uyarı-iletim sistemi nasıl değerlendirilir?","steps":[{"t":"EKG nedir","a":"Elektriksel etkinliği kaydeder","d":"EKG, kalpteki uyarının yarattığı elektriksel etkinliği vücut yüzeyinden kaydeden bir yöntemdir. Uyarının yayılması belirli dalgalar olarak görülür."},{"t":"Dalgaların anlamı","a":"Kulakçık ve karıncık etkinliği","d":"EKG dalgaları kulakçıkların ve karıncıkların uyarılıp kasılmasını yansıtır. Bir dalga kulakçık, diğer dalgalar karıncık etkinliğini gösterir."},{"t":"Tanı değeri","a":"İletim bozuklukları görülür","d":"Bu dalgaların biçimi ve zamanlaması iletim sistemindeki aksaklıkları ortaya koyar. Böylece AV blok veya ritim bozukluğu gibi sorunlar tespit edilebilir."}],"ans":"EKG, kalbin uyarısının yarattığı elektriksel etkinliği kaydeder; dalgaların biçim ve zamanlamasından kulakçık-karıncık etkinliği ve iletim bozuklukları değerlendirilir."},{"q":"Yapay kalp pili (pacemaker) takılması hangi durumda gerekir ve nasıl çalışır?","steps":[{"t":"Gerekli durum","a":"Doğal pil yetersiz","d":"SA düğümü düzgün uyarı üretemez veya iletim bozulursa kalp çok yavaş ya da düzensiz atar. Bu durumda doğal pil görevini yerine getiremez."},{"t":"Yapay pilin işlevi","a":"Düzenli uyarı verir","d":"Yapay kalp pili, kalbe düzenli aralıklarla elektriksel uyarılar göndererek atışı düzenler. Böylece eksik veya düzensiz uyarının yerini alır."},{"t":"Sonuç","a":"Kalp düzenli atar","d":"Yapay pil sayesinde kalp yeterli ve düzenli bir hızda atmaya devam eder. Bu da dokulara yeterli kan gitmesini sağlar."}],"ans":"Doğal pil (SA düğümü) veya iletim yetersiz kaldığında yapay pil takılır; düzenli elektriksel uyarılar vererek kalbin yeterli ve düzenli atmasını sağlar."},{"q":"Adrenalin hormonunun kalbe etkisini, salgılandığı durum ve mekanizmayla açıklayınız.","steps":[{"t":"Salgılandığı durum","a":"Stres, korku, heyecan","d":"Adrenalin, korku, heyecan veya egzersiz gibi durumlarda böbreküstü bezinden kana salgılanır. Vücudun hızlı tepki vermesi gereken anlarda devreye girer."},{"t":"Kalbe etkisi","a":"SA düğümünü uyarır","d":"Kana karışan adrenalin SA düğümünü uyararak kalp hızını ve kasılma gücünü artırır. Böylece kalp daha çok kan pompalar."},{"t":"İşlevsel sonuç","a":"Organlara bol kan","d":"Hızlanan dolaşım kaslara ve organlara daha fazla oksijen ve enerji ulaştırır. Bu, vücudun tehlikeye veya çabaya hazır olmasını sağlar."}],"ans":"Adrenalin stres ve egzersizde salgılanır, SA düğümünü uyararak kalp hızını ve gücünü artırır; böylece organlara bol kan giderek vücut çabaya hazırlanır."},{"q":"Kalbin kendi ritmini koruması ile sinir-hormon düzenlemesi arasındaki ilişkiyi açıklayınız.","steps":[{"t":"Temel ritim","a":"SA düğümü belirler","d":"Kalbin temel atış ritmi, herhangi bir dış etki olmadan SA düğümü tarafından üretilir. Bu, kalbin kendi otomatik çalışmasıdır."},{"t":"Dış düzenleme","a":"Sinir ve hormon hızı değiştirir","d":"Otonom sinirler ve adrenalin gibi hormonlar bu temel ritmi başlatmaz, sadece hızlandırır veya yavaşlatır. Yani düzenleyici rol oynarlar."},{"t":"İlişki","a":"Otomatizm + ayarlama","d":"Kalp kendi ritmini bağımsız üretirken, sinir ve hormonlar bu ritmi vücudun ihtiyacına göre ayarlar. Böylece kalp hem bağımsız çalışır hem de duruma uyum sağlar."}],"ans":"Kalbin temel ritmini SA düğümü bağımsız üretir; otonom sinirler ve hormonlar bu ritmi başlatmaz, yalnızca vücut ihtiyacına göre hızlandırıp yavaşlatarak ayarlar."},{"q":"Karıncıkların kulakçıklardan kısa bir gecikmeyle kasılması bir tam kalp döngüsünü nasıl düzenler?","steps":[{"t":"Kulakçık kasılması","a":"Karıncığı doldurur","d":"SA uyarısıyla önce kulakçıklar kasılır ve karıncıkları kanla tam doldurur. Bu, döngünün ilk aşamasıdır."},{"t":"AV gecikmesi","a":"Doluma zaman tanır","d":"AV düğümündeki kısa gecikme, karıncıkların kasılmadan önce tam dolmasını sağlar. Bu zamanlama olmadan pompalama verimsiz olurdu."},{"t":"Karıncık kasılması","a":"Kanı pompalar","d":"Gecikmenin ardından karıncıklar kasılarak kanı atardamarlara pompalar. Böylece kulakçık ve karıncık kasılmaları uyumlu bir döngü oluşturur."}],"ans":"Önce kulakçıklar kasılıp karıncığı doldurur, AV gecikmesi tam doluma zaman tanır, sonra karıncıklar kasılarak kanı pompalar; bu sıralı zamanlama verimli bir kalp döngüsü oluşturur."},{"q":"İletim sisteminde His demetinin (AV demeti) hasar görmesi (blok) ne tür bir soruna yol açar?","steps":[{"t":"His demetinin görevi","a":"Uyarıyı karıncıklara taşır","d":"His demeti, AV düğümünden gelen uyarıyı karıncıklara ileten köprüdür. Bu yol kesintiye uğrarsa uyarı karıncıklara ulaşamaz."},{"t":"Blok durumu","a":"Kulakçık-karıncık bağı kopar","d":"His demeti hasar görürse kulakçıklardan gelen uyarı karıncıklara iletilemez. Buna kalp bloğu denir."},{"t":"Sonuç","a":"Karıncıklar kendi yavaş ritmiyle atar","d":"Bu durumda karıncıklar kendi yavaş uyarılarıyla, kulakçıklardan bağımsız atmaya başlar. Kalp hızı düşer ve pompalama verimi azalır."}],"ans":"His demeti hasar görürse kulakçık uyarısı karıncıklara iletilemez (kalp bloğu); karıncıklar kendi yavaş ritmiyle atar ve kalp hızı ile pompalama verimi düşer."},{"q":"Sporcuların dinlenme kalp hızının normalden düşük olması uyarı sistemiyle nasıl ilişkilidir?","steps":[{"t":"Antrenmanlı kalp","a":"Daha güçlü ve verimli","d":"Düzenli antrenman kalp kasını güçlendirir ve her atışta daha çok kan pompalamasını sağlar. Böylece aynı kanı pompalamak için daha az atış yeterli olur."},{"t":"Parasempatik baskınlık","a":"Vagus etkisi artar","d":"Antrenmanlı kişilerde dinlenmede parasempatik (vagus) etkinliği daha baskındır. Bu, SA düğümünü daha fazla baskılayarak kalp hızını düşürür."},{"t":"Sonuç","a":"Düşük dinlenme nabzı","d":"Güçlü kalp ve baskın parasempatik etki birleşince dinlenme kalp hızı normalden düşük olur. Bu, sağlıklı ve verimli bir kalbin göstergesidir."}],"ans":"Antrenmanlı kalp her atışta daha çok kan pompalar ve dinlenmede parasempatik etki SA düğümünü daha çok baskılar; bu yüzden sporcuların dinlenme nabzı düşüktür."}]}}};
